window.__QUIZ_SUBJECT__=[{"id": "objective>Data Processing>2016>1", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Who among the following scientist invented the punch card?", "images": [], "options": {"A": "blaise pascal", "B": "charles babbage", "C": "gottfried wilhelm", "D": "herman hollerith"}, "answer": "D", "explanation": "Hollerith first got his idea for the punch-card tabulation machine from watching a train conductor punch tickets. For his tabulation machine he used the punch card invented in the early 1800s", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>2", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following computers in designed to performed variety of tasks?", "images": [], "options": {"A": "Analogue", "B": "Digital", "C": "General purpose", "D": "Hybrid"}, "answer": "C", "explanation": "A general-purpose computer is designed to perform a variety of tasks. Unlike special-purpose computers, which are designed for a single task, general-purpose computers can run any application that is compatible with their operating system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>3", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The special feature in word processing which allows the sending of multiple data copies of document to different people without having it retyped is", "images": [], "options": {"A": "cut and paste", "B": "insert", "C": "mail merge", "D": "thesaurus"}, "answer": "C", "explanation": "Mail merge the automatic addition of names and addresses from a database to letters and envelopes in order to facilitate sending mail, especially advertising, to many addresses.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>4", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "A motion path is a", "images": [], "options": {"A": "methods of advancing slide", "B": "methods of moving items on slide", "C": "path to follow when starting powerpoint", "D": "path to save powerpoint file"}, "answer": "B", "explanation": "A motion path in the context of PowerPoint is a way of moving items on a slide. It's a type of animation that allows you to move an object in a specified path around the slide. This can be used to guide the viewer's attention or to create a dynamic effect.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>5", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Which of the following can be used to make a powerpoint slide in a presentation to have the same look?", "images": [], "options": {"A": "Add a little slide option", "B": "Add presentation design template", "C": "Change the view to slide show", "D": "Format the slide layout option"}, "answer": "B", "explanation": "A PowerPoint template is a pattern or blueprint of a slide or group of slides that you save as a .potx file. Templates can contain layouts, theme colors, theme fonts, theme effects, background styles, and even content. You can create your own custom templates and store them, reuse them, and share them with others", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>6", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The correctness and completeness of a data in a database is its", "images": [], "options": {"A": "constraint", "B": "independence", "C": "integrity", "D": "redundancy"}, "answer": "C", "explanation": "Data integrity is the maintenance of, and the assurance of the accuracy and consistency of, data over its entire ... This type of integrity is concerned with the correctness or rationality of a piece of data, given a particular context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>7", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following conditions is used to transmit packets over a medium at the same time?", "images": [], "options": {"A": "Asynchronous", "B": "Contention", "C": "Collision", "D": "Synchronous"}, "answer": "B", "explanation": "Contention is the correct answer. Contention is a condition that arises when two or more data stations attempt to transmit at the same time over a shared channel, or when two data stations attempt to transmit at the same time through an interconnecting device where there is a single path for data flow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>8", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Which of the following is not a normal form of relational database?", "images": [], "options": {"A": "1NF", "B": "2NF", "C": "3NF", "D": "4NF"}, "answer": "D", "explanation": "Fourth Normal Form (4NF)    A table is said to be in the Fourth Normal Form when,        It is in the Boyce-Codd Normal Form.      And, it doesn't have Multi-Valued Dependency", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>9", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The two major types of computer chips are", "images": [], "options": {"A": "external memory chip", "B": "primary memory chip", "C": "microprocessor chip", "D": "both b and c"}, "answer": "D", "explanation": "The two major types of computer chips are primary memory chips and microprocessor chips. Primary memory chips are used for temporary storage of data and instructions that the computer is currently working with (RAM). Microprocessor chips are the 'brain' of the computer where most calculations take place.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>10", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "which of the following is an advantage of electronic data processing?", "images": [], "options": {"A": "automatic operation", "B": "automated backup", "C": "mass storage", "D": "resource sharing"}, "answer": "A", "explanation": "From a financial perspective alone, there are impressive benefits from implementing EDI. Exchanging documents electronically improves transaction speed and visibility while decreasing the amount of money you spend on manual processes. But cost savings is far from the only benefit of using EDI.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>11", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The following are examples of relational operators except", "images": [], "options": {"A": "", "B": ">", "C": "=", "D": "*"}, "answer": "D", "explanation": "Therefore, \"*\" is not an examples of a relational operator.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>12", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "A/An _____ in a database represents a relationship among a set of values", "images": [], "options": {"A": "Column", "B": "Entity", "C": "Entry", "D": "key"}, "answer": "B", "explanation": "An entity is any object in the system that we want to model and store information about. Entities are usually recognizable concepts, either concrete or abstract, such as person, places, things, or events which have relevance to the database. Some specific examples of entities are Employee, Student, Lecturer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>13", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Strategic data modeling is the", "images": [], "options": {"A": "capturing and displaying of program data", "B": "creation of an information system procedure", "C": "development of logical data  models", "D": "implementation of the blueprint in database"}, "answer": "C", "explanation": "Logical data models are representations of the data that a business needs to collect and manage in order to achieve its goals. Strategic data modeling is the process of developing these logical data models to support the long-term needs of the business.    Strategic data modeling involves understanding the business's goals, identifying the data that is needed to achieve those goals, and designing a logical data model that will support the efficient and effective use of that data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>14", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "A data model has how many components?", "images": [], "options": {"A": "2", "B": "3", "C": "4", "D": "5"}, "answer": "B", "explanation": "A data model theory has three main components: The structural part: a collection of data structures which are used to create databases representing the entities or objects modeled by the database", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>15", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "How many type (s) of index (es) is/are there in structured query language server?", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "4"}, "answer": "B", "explanation": "Clustered: Clustered indexes sort and store the data rows in the table or view based on their key values.       Nonclustered: Nonclustered indexes have a structure separate from the data rows.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>16", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following is an audio visual medium of receiving information?", "images": [], "options": {"A": "fax", "B": "film strip", "C": "flip chart", "D": "television"}, "answer": "D", "explanation": "Audiovisual (AV) means possessing both a sound and a visual component, such as slide-tape presentations, films, television programs, church services and live theater productions. ... Another audiovisual expression is the visual presentation of sound (visual music).", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>17", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The following are examples of operating system by microsoft corporation except", "images": [], "options": {"A": "ms-dos", "B": "os/2", "C": "xp", "D": "vista"}, "answer": "B", "explanation": "OS/2 is a series of computer operating systems, initially created by Microsoft and IBM under the leadership of IBM software designer Ed Iacobucci.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>18", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Software that defines a database, stores the data, supports a query language, produces reports and creates data entry screens is a", "images": [], "options": {"A": "data dictionary", "B": "database management system (DBMS)", "C": "decision support system", "D": "relational database"}, "answer": "B", "explanation": "The role of a DBMS in a larger system is to allow other software, or users, to store and retrieve data in a structured way. A \"Database management system is a software that defines a database , stores the data, supports a query language, produces reports, and create data entry screens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>19", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The database design that consists of multiple tables that are linked together through matching data stored in each table is called a:", "images": [], "options": {"A": "object oriented database", "B": "hierarchical database", "C": "network database", "D": "relational data base"}, "answer": "D", "explanation": "The relational database model consists of tables with each table having rows and columns. Each row represents a record and data in columns represents fields. The tables are linked together via common fields, thus making it easy to access any data in the database tables (provided access is granted to the data). Any table can be accessed without having to go through a hierarchy. A table can be linked to any number of parent tables and a parent table can have any number of child tables.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>20", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which of the following items is not the advantage of a DBMS?", "images": [], "options": {"A": "improved ability to enforce standards", "B": "Improved data consistency", "C": "Local control over the data", "D": "Minimal data redundancy"}, "answer": "C", "explanation": "The advantage of a Database Management System (DBMS) is that it provides a centralized view and control over data. Local control over the data is not an advantage of DBMS as it can lead to inconsistencies and data redundancy. In a DBMS, data is stored in a centralized manner and access is controlled by the database administrator.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>21", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The feature in word processing which compares every word with an electronic dictionary is", "images": [], "options": {"A": "help", "B": "page alignment", "C": "spell check", "D": "thesaurus"}, "answer": "C", "explanation": "A word processor is software or a device that allows users to create, edit, and print ... spell checking: Identifies words that don't appear in a standard dictionary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>22", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Which of the following is not a database security tip?", "images": [], "options": {"A": "updating of Anti mal ware software", "B": "enforce restriction on internet access", "C": "fight off hacking attacks with intrusion detection technology", "D": "regular backup of data on removable media"}, "answer": "D", "explanation": "Regular backup of data on removable media is not a database security tip. While it is important to regularly backup data, doing so on removable media can actually pose a security risk if the media is lost or stolen. Instead, data should be backed up in a secure, off-site location or on the cloud. The other options listed are all valid security tips for databases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>23", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The process of distribution information over communication network or medium is referred to as", "images": [], "options": {"A": "acquisition", "B": "interpretation", "C": "organisation", "D": "transmission"}, "answer": "D", "explanation": "Data communications refers to the transmission of this digital data between two or more ... computing devices is established using either cable media or wireless media. ... and servers, and allows the computers to communicate over the network. .", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>24", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Computer stores data in unit called", "images": [], "options": {"A": "bit", "B": "database", "C": "field", "D": "file"}, "answer": "A", "explanation": "Abbreviation for binary term, a unit of storage capable of holding a single character. On almost all modern computers, a byte is equal to 8 bits. Large amounts of memory are indicated in terms of kilobytes (1,024 bytes), megabytes (1,048,576 bytes), and gigabytes (1,073,741,824 bytes).", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>25", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "How do u minimize and maximize windows?", "images": [], "options": {"A": "At the top right corner click Dash or Square", "B": "Go to file and select minimize or minimize", "C": "Hold down both right and left button on the mouse", "D": "It is an impossible task"}, "answer": "A", "explanation": "To minimize and maximize windows, you typically click on the dash or square icons at the top right corner of the window. The dash usually minimizes the window, while the square maximizes it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>26", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Excel worksheet version 8 has how many columns?", "images": [], "options": {"A": "65,533", "B": "65,534", "C": "65,535", "D": "65,536"}, "answer": "D", "explanation": "Versions 8.0 through 11.0 could handle 64K (216 = 65536) rows and 256 columns", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>27", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the function keys opens the \"Save-As\" windows in MS word?", "images": [], "options": {"A": "F1", "B": "F10", "C": "F12", "D": "F2"}, "answer": "C", "explanation": "The F12 Key – Save As  F12, the final function key, is used mostly in Microsoft Office. If you want to save your document, workbook, or slideshow with a different name or to a different location, tap F12 to bring up the Save As dialog. Ctrl+F12 will start the Open File dialog.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>28", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Multitasking allows the _____ to access several programs at the same time", "images": [], "options": {"A": "computer", "B": "cpu", "C": "ram", "D": "user"}, "answer": "D", "explanation": "Multitasking allows the user to access several programs at the same time. This is a feature of modern operating systems that allows multiple applications to run concurrently. While technically it's the computer's CPU that switches between tasks, from the user's perspective, it appears as if several programs are running at the same time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>29", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Which of the following fields can uniquely identify a record of student's performance in a school?", "images": [], "options": {"A": "Administration number", "B": "Classroom number", "C": "Date of birth", "D": "First name"}, "answer": "A", "explanation": "The administration number is a unique identifier assigned to each student in a school. It is used to track the student's performance and other details. Classroom number, date of birth, first name, and surname can be shared by multiple students, hence they cannot uniquely identify a student's record.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>30", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The execution of an instruction by a processor is in three distinct phases.They are", "images": [], "options": {"A": "call, respond, store", "B": "fetch, decode, execute", "C": "input, output, process", "D": "start, stop, process"}, "answer": "B", "explanation": "There are six fundamental phases of the instruction cycle: fetch instruction (aka pre-fetch) decode instruction. evaluate address (address generation)", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>31", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The function of the history link in the standard navigation bar of an internet explorer is to", "images": [], "options": {"A": "display a list of previously bookmarked  website", "B": "display a list of previously viewed website", "C": "go to the homepage of currently viewed website", "D": "move forward to a webpage viewed before using the back button"}, "answer": "B", "explanation": "History button: The history function allows you to view and select Web pages you have visited within the last 20 days. You can sort your items by clicking on the black triangle to the right of the word View. You can sort by size, date, the number of times visited, and the order you have visited today.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>32", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The roles of a database administrator includes the following except", "images": [], "options": {"A": "aiding an abetting fraud", "B": "backup and receiving the database", "C": "creating new databases", "D": "ensuring database security is implemented to safeguard the data"}, "answer": "A", "explanation": "The role may include capacity planning, installation, configuration, database design, migration, performance monitoring, security, troubleshooting, as well as backup and data recovery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>33", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Ctrl + B", "images": [], "options": {"A": "search the selected text", "B": "paste the selected text", "C": "bold the selected text", "D": "open the specified file"}, "answer": "C", "explanation": "Ctrl + B is a keyboard shortcut that is commonly used in various programs to bold the selected text. It does not search, paste, or open files.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>34", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "The following are the benefits of parallel databases except", "images": [], "options": {"A": "availability", "B": "complexity", "C": "high performance", "D": "reliability"}, "answer": "B", "explanation": "Parallel databases are designed to ensure high performance, availability, reliability, and usability. Managing a parallel database can be more complex than managing a non-parallel database because data must be distributed across multiple servers and queries must be executed in parallel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>35", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "The slide that is used to introduce a topic during presentation is called", "images": [], "options": {"A": "animation", "B": "bullet", "C": "graph", "D": "title slide"}, "answer": "D", "explanation": "A title slide in PowerPoint can take on many different definitions, but in most cases, it is the first slide in the slide deck and appears in the PowerPoint workspace when that presentation is opened. By default in PowerPoint, the title slide offers two text boxes for a title and subtitle.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>36", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Word has a list of predefined typing, spelling, capitalization, and grammar errors that _____ can detect and correct.", "images": [], "options": {"A": "autoentry", "B": "autocorrect", "C": "autoadd", "D": "autoSpell"}, "answer": "B", "explanation": "Word has a list of predefined typing, spelling, capitalization, and grammar errors that autocorrect can detect and correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>37", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The process of converting data or information into a form which is readily for processing is called", "images": [], "options": {"A": "analysing", "B": "decoding", "C": "encoding", "D": "manipulating"}, "answer": "C", "explanation": "The process of converting data or information into a form which is readily for processing is called 'encoding'. Encoding is the process of converting data from one form to another form, especially in computing and digital communications.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>38", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The ring technology is a protocol at which layer of the OSI model?", "images": [], "options": {"A": "datalink", "B": "network", "C": "presentation", "D": "session"}, "answer": "A", "explanation": "The ring technology is a protocol at the Data Link layer of the OSI model. The OSI model (Open Systems Interconnection model) is a conceptual model that characterizes and standardizes the communication functions of a telecommunication or computing system without regard to its underlying internal structure and technology. The Data Link layer is the second layer in the OSI model and is responsible for data transfer across the physical layer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>39", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Where was Abacus invented?", "images": [], "options": {"A": "argentina", "B": "australian", "C": "china", "D": "egypt"}, "answer": "C", "explanation": "The first Chinese Abacus was invented around 500 B.C. The Abacus, as we know it today, was used in China around 1300 A.D.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>40", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "A program installed on a computer  that secretly collects information about the user is called", "images": [], "options": {"A": "ad ware", "B": "fire wall", "C": "malware", "D": "spyware"}, "answer": "D", "explanation": "Spyware is unwanted software that infiltrates your computing device, stealing your internet usage data and sensitive information. Spyware is classified as a type of malware — malicious software designed to gain access to or damage your computer, often without your knowledge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>41", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Desktops, laptops,palmtops, PDAs and tables are examples of a _____computer", "images": [], "options": {"A": "hybrid", "B": "mainframe", "C": "micro", "D": "mini"}, "answer": "C", "explanation": "Microcomputer    Desktop computers, laptops, personal digital assistant (PDA), tablets & smartphones are all types of microcomputers. The micro-computers are widely used & the fastest growing computers. These computers are the cheapest among the other three types of computers. The Micro-computers are specially designed for general usage like entertainment, education and work purposes. Well known manufacturers of Micro-computer are Dell, Apple, Samsung, Sony & Toshiba.    Desktop computers, Gaming consoles, Sound & Navigation system of a car, Netbooks, Notebooks, PDA's, Tablet PC's, Smartphones, Calculators are all type of Microcomputers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>42", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Numbers that are written to base 16 are classified as", "images": [], "options": {"A": "ASCII", "B": "binary", "C": "decimal", "D": "hexadecimal"}, "answer": "D", "explanation": "In mathematics, a subscript is typically used to specify the radix. For example the decimal value10,995 would be expressed in hexadecimal as 2AF316. In programming, a number of notations are used to support hexadecimal representation, usually involving a prefix or suffix.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>43", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "Microchip is the technology behind which generation of computer?", "images": [], "options": {"A": "fifth", "B": "first", "C": "fourth", "D": "second"}, "answer": "C", "explanation": "Microchip technology is associated with the fourth generation of computers. The fourth generation of computers is characterized by the use of microprocessors, which contain thousands of integrated circuits (ICs). This technology allowed computers to become smaller, faster, cheaper, more energy-efficient and more reliable than their first-generation predecessors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>44", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Computer ethics is defined as", "images": [], "options": {"A": "a branch of philosophy concerned with what is right and what is wrong", "B": "an aspect of computing concerned with  standard of conduct as pertain with computers", "C": "criminal activities done using a computer and the internet", "D": "protection provided by law authors of original work"}, "answer": "B", "explanation": "Computer ethics is a part of practical philosophy concerned with how computing professionals should make decisions regarding professional and social conduct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>45", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the following key or combinations of key starts a new paragraph in MS-word?", "images": [], "options": {"A": "Enter", "B": "Ctrl+Enter", "C": "Down cursor", "D": "Shift+Enter"}, "answer": "A", "explanation": "In Microsoft Word, pressing the 'Enter' key starts a new paragraph. The 'Ctrl+Enter' key combination inserts a page break, not a new paragraph. The 'Down cursor', 'Shift+Enter', and 'Space bar' do not start a new paragraph.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>46", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The recovery manager______consists of various application and database that plays a role in backup and recovery strategy", "images": [], "options": {"A": "Console", "B": "document", "C": "environment", "D": "file"}, "answer": "A", "explanation": "The recovery manager console consists of various application and database that plays a role in backup and recovery strategy", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>47", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Computer ____is the practice of keeping it in a good functioning state.", "images": [], "options": {"A": "compilation", "B": "debugging", "C": "evacuation", "D": "maintenance"}, "answer": "D", "explanation": "Computer maintenance is the practice of keeping computers in a good state of repair. A computer containing accumulated dust and debris may not run properly. Dust and debris will accumulate as a result of air cooling. Any filters used to mitigate this need regular service and changes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>48", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "In the _____Method of data transfer, the participation of the processor is eliminated.", "images": [], "options": {"A": "buffering", "B": "caching", "C": "direct memory access", "D": "indirect memory access"}, "answer": "C", "explanation": "Direct memory access (DMA) is a method that allows an input/output (I/O) device to send or receive data directly to or from the main memory, bypassing the CPU to speed up memory operations. The process is managed by a chip known as a DMA controller (DMAC).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>49", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following storage media has the smallest capacity?", "images": [], "options": {"A": "Compact disc", "B": "Flash drive", "C": "Floppy diskette", "D": "Hard drive"}, "answer": "C", "explanation": "In the late 80's, the 5.25-inch floppy disk was on its way out and in 1987 the 3.5-inch floppy disk had moved into the high density category with a capacity of 1.44 MB", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>50", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "A computer program that is capable of continually  replicating itself with little or no user interaction is called?", "images": [], "options": {"A": "rootkit", "B": "spyware", "C": "trojan", "D": "worm"}, "answer": "D", "explanation": "Worms spread from computer to computer, but unlike a virus, it has the capability to travel without any help from a person", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>51", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The stored program used to solve the problem of writing board in EDVAC was developed by", "images": [], "options": {"A": "haward aiken", "B": "john mauchly", "C": "john von neuman", "D": "maurice wikes"}, "answer": "C", "explanation": "EDVAC (Electronic Discrete Variable Automatic Computer) was one of the earliest electronic computers. Unlike its predecessor the ENIAC, it was binary rather than decimal, and was a stored-program computer. ENIAC inventors John Mauchly and J. Presper Eckert proposed the EDVAC's construction in August 1944.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>52", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "The following are ways of ensuring safety in the computer laboratory except", "images": [], "options": {"A": "arranging all chairs and tables in a comfortable manner for users", "B": "concealing all the electrical cables and connections", "C": "eating and drinking in the computer room", "D": "switching off all the electrical appliance at the end of the day's work"}, "answer": "C", "explanation": "Eating and drinking in the computer room is not a way of ensuring safety in the computer laboratory. In fact, it is discouraged because it can lead to accidents such as spillage on the computer equipment which can cause damage or even electrical hazards.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>53", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Which of the  best define information processing? The", "images": [], "options": {"A": "capturing of information by computer", "B": "manipulation of information by computer", "C": "retrieval of information from computer", "D": "storage information in computer"}, "answer": "B", "explanation": "A process is an instance of a program running in a computer. It is close in meaning to task , a term used in some operating systems. In UNIX and some other operating systems, a process is started when a program is initiated (either by a user entering a shell command or by another program).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>54", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Media recovery deals with _____errors", "images": [], "options": {"A": "disk", "B": "power", "C": "read", "D": "system"}, "answer": "A", "explanation": "In computing, data recovery is a process of salvaging (retrieving) inaccessible, lost, corrupted, damaged or formatted data from secondary storage, removable media or files, when the data stored in them cannot be accessed in a normal way. The data is most often salvaged from storage media such as internal or external hard disk drives (HDDs), solid-state drives (SSDs), USB flash drives, magnetic tapes, CDs, DVDs, RAID subsystems, and other electronic devices. Recovery may be required due to physical damage to the storage devices or logical damage to the file system that prevents it from being mounted by the host operating system (OS)", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>55", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "When creating a database, the data dealing with entity is modeled as a/an", "images": [], "options": {"A": "attribute", "B": "class", "C": "object", "D": "record"}, "answer": "A", "explanation": "Describes the type of the information that is being mastered. An entity type typically corresponds to one or several related tables in database. Attribute. A characteristic or trait of an entity type that describes the entity, for example, the Person entity type has the Date of Birth attribute.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>56", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "What device separates a single network into into two segments, but allows the two segments appear as one to higher protocols?", "images": [], "options": {"A": "Bridge", "B": "Gateway", "C": "Modem", "D": "Router"}, "answer": "A", "explanation": "A bridge is a type of computer network device that provides interconnection with other bridge networks that use the same protocol. Bridge devices work at the data link layer of the Open System Interconnect (OSI) model, connecting two different networks together and providing communication between them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>57", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "The _____helps you create a standardized group of slides with familiar look", "images": [], "options": {"A": "autocontent wizard", "B": "design template", "C": "header and footer", "D": "page setup"}, "answer": "B", "explanation": "A PowerPoint template is a pattern or blueprint of a slide or group of slides that you save as a .potx file. Templates can contain layouts, theme colors, theme fonts, theme effects, background styles, and even content. You can create your own custom templates and store them, reuse them, and share them with others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2016>58", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Which of the following is an example of graphic software package?", "images": [], "options": {"A": "Instant artist", "B": "MS Access", "C": "Notepad", "D": "Open office impress"}, "answer": "A", "explanation": "Instant Artist is an example of a graphic software package. Graphic software packages are used to create, edit, and manage 2D visuals such as images, clip art, and digital art. Instant Artist, also known as Print Artist, is a graphic software that provides users with various tools to create a wide range of projects like cards, banners, and more.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>59", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The _____computer is used in scientific application, engineering fields and industrial control process", "images": [], "options": {"A": "analogue", "B": "digital", "C": "hybrid", "D": "super"}, "answer": "D", "explanation": "Supercomputers play an important role in the field of computational science, and are used for a wide range of computationally intensive tasks in various fields, including quantum mechanics, weather forecasting, climate research, oil and gas exploration, molecular modeling (computing the structures and properties of chemical compounds, biological macromolecules, polymers, and crystals), and physical simulations (such as simulations of the early moments of the universe, airplane and spacecraft aerodynamics, the detonation of nuclear weapons, and nuclear fusion", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2016>60", "subject": "Data Processing", "year": "2016", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "What type of secondary storage device provides sequential access to data?", "images": [], "options": {"A": "Floppy disk", "B": "Liquid crystal display", "C": "Magnetic core storage", "D": "Magnetic tape"}, "answer": "D", "explanation": "Sequential access memory. In computing, sequential access memory (SAM) is a class of data storage devices that read stored data in a sequence. This is in contrast to random access memory (RAM) where data can be accessed in any order. Sequential access devices are usually a form of magnetic storage or optical storage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>1", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "One characteristic feature of the present generation computers is the presence of", "images": [], "options": {"A": "vacuum tubes", "B": "transistors", "C": "micro-chips", "D": "integrated circuit"}, "answer": "D", "explanation": "Characteristics of third generation computers include:        Integrated circuits instead of individual transistors.      Smaller, cheaper, more efficient and faster than second generation computers.      High-level programming languages.      Magnetic storage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>2", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Convert 410 to a number in base 2", "images": [], "options": {"A": "10", "B": "11", "C": "100", "D": "110"}, "answer": "C", "explanation": "The number 4 in base 10 is equivalent to 100 in base 2. This is because 4 can be expressed as 2^2, and in binary representation, this is written as 100.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>3", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Data processed into its useful form is referred to as", "images": [], "options": {"A": "unique data", "B": "raw data", "C": "knowledge", "D": "information"}, "answer": "D", "explanation": "Data processing is, generally, \"the collection and manipulation of items of data to produce meaningful information.\" In this sense it can be considered a subset of information processing, \"the change (processing) of information in any manner detectable by an observer.\"", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>4", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following is an example of qualitative data?", "images": [], "options": {"A": "colour", "B": "height", "C": "length", "D": "shoe size"}, "answer": "A", "explanation": "Qualitative analysis shows whether a particular substance is present, but does not give an indication of how much is present. Examples of qualitative analysis for metal ions include flame and precipitate tests. Examples for non-metal ions include halide and ammonium ion tests. Some examples of qualitative data are the softness of your skin, the grace with which you run, and the color of your eyes. However, try telling Photoshop you can't measure color with numbers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>5", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following is not a characteristics of a personal computer?", "images": [], "options": {"A": "Automation", "B": "Complex", "C": "Digital", "D": "High speed"}, "answer": "B", "explanation": "Essential Computer Features for Personal computer:        Type of Processor. The higher the speed of the processor, the faster the computer will be able to handle multiple programs and activities. ...      Hard Drive. ...      Random Access Memory (RAM) ...      Dual Monitor Options. ...      Display Type. ...      Wireless Connectivity. ...      Operating System. ...      Graphics Card.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>6", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The gap between ownership, access and benefits from computer and its application is termed digital", "images": [], "options": {"A": "Separation", "B": "Divide", "C": "Deprivation", "D": "Annihilation"}, "answer": "B", "explanation": "The term 'digital divide' refers to the gap between those who have ready access to computers and the Internet, and those who do not. This is a significant issue, particularly in developing countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>7", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Magnetic Ink Character Recognition (MICR) are used to read codes on", "images": [], "options": {"A": "postal orders", "B": "multiple Choice Examination answer sheet", "C": "bank tellers", "D": "bank cheques"}, "answer": "D", "explanation": "(magnetic ink character recognition) is a technology used to verify the legitimacy or originality of paper documents, especially bank cheques.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>8", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The device that sends information to the CPU is the", "images": [], "options": {"A": "Bus", "B": "Input device", "C": "Output device", "D": "Processor"}, "answer": "B", "explanation": "An input device is a hardware or peripheral device used to send data to the computer. An input device sends information to the Central Processing Unit (CPU) when a user interacts with it. Examples of input devices include keyboards, mouse, scanners, digital cameras, joysticks, and microphones.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>9", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Which of the following is not a procedure for Information processing?", "images": [], "options": {"A": "Segregation", "B": "Organisation", "C": "Interpretation", "D": "Collation"}, "answer": "A", "explanation": "Information processing cycle The sequence of events in processing information, which includes (1) input, (2) processing, (3) storage and (4) output. The input stage can be further broken down into acquisition, data entry and validation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>10", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The assembling of data according to a predetermined order is known as", "images": [], "options": {"A": "collation", "B": "interpretation", "C": "organisation", "D": "summarization"}, "answer": "A", "explanation": "Collation is the assembly of written information into a standard order. Many systems of collation are based on numerical order or alphabetical order, or extensions and combinations thereof. Collation is a fundamental element of most office filing systems, library catalogs and reference books.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>11", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Information Transmission Medium from location P to location Q in space is called", "images": [], "options": {"A": "Wireless transmission", "B": "Wired transmission", "C": "Cabled transmission", "D": "Asynchronous Transmission"}, "answer": "A", "explanation": "A transmission medium is a material substance (solid, liquid, gas, or plasma) that can propagate energy waves. For example, the transmission medium for sounds is usually a gas, but solids and liquids may also act as a transmission medium for sound.   Wireless transmission is a form of unguided media. Wireless communication involves no physical link established between two or more devices, communicating wirelessly. Wireless signals are spread over in the air and are received and interpreted by appropriate antennas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>12", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following is not a type of wireless transmission?", "images": [], "options": {"A": "bluetooth", "B": "fibre optic", "C": "infrared", "D": "wifi"}, "answer": "B", "explanation": "Types of wireless communications.        Types of Wireless Communciation.      Satellite Communciaiton.      Infrared Communication.      Broadcast Radio.      Radio.      Microwave Communication.      Wi-Fi Communication.      Mobile Communication Systems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>13", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The basic criterion for classifying a network is", "images": [], "options": {"A": "psychological consideration", "B": "geographical scope", "C": "equipment avaliability", "D": "economic reason"}, "answer": "B", "explanation": "Network Classifications. Computer networks are typically classified by scale, ranging from small, personal networks to global wide-area networks and the Internet itself. The following readings provide detailed information on the common network classification", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>14", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Which of the following measures are used to secure data online?    I.  Password  II. Encryption  III. Personal Identification Number (PIN)", "images": [], "options": {"A": "II only", "B": "III only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "All three measures are used to secure data online. A password is a secret word or phrase that must be used to gain admission to a place. Encryption is the process of converting information or data into a code, especially to prevent unauthorized access. A Personal Identification Number (PIN) is a numerical code used in many electronic financial transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>15", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "In email context, bcc stands for", "images": [], "options": {"A": "Backup carbon copy", "B": "Blank carbon copy", "C": "Blind carbon copy", "D": "Bulk carbon copy"}, "answer": "C", "explanation": "In the context of email, BCC stands for 'Blind Carbon Copy'. This is a way of sending copies of an email to multiple people without them knowing who else is receiving the email. Any recipients on the Bcc line of an email are not visible to others on the email.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>16", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "An Internet-based system that allows people of different geographical locations to have In-person meeting is known as", "images": [], "options": {"A": "Voice messaging system", "B": "Video conferencing system", "C": "Online mailing system", "D": "Fax system"}, "answer": "B", "explanation": "Video conferencing (or video conference) means to conduct a conference between two or more participants at different sites by using computer networks to transmit audio and video data. For example, a point-to-point (two-person) video conferencing system works much like a video telephone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>17", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The following software program coordinate and control all other computer programs, hardware and Users' actions except", "images": [], "options": {"A": "zeneth", "B": "unix", "C": "dos", "D": "dbms"}, "answer": "D", "explanation": "DBMS (Database Management System) is not a software program that coordinates and controls all other computer programs, hardware and users' actions. DBMS is a software for creating and managing databases. It provides users with a systematic way to create, retrieve, update and manage data. Zeneth, Unix, and DOS are all operating systems that manage hardware resources, software applications, and users' actions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>18", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "In Word processing applications, the symbols B, / and U are commonly used buttons found on the", "images": [], "options": {"A": "Standard toolbar", "B": "Menu bar", "C": "Formatting toolbar", "D": "Drawing toolbar"}, "answer": "C", "explanation": "The formatting toolbar is a toolbar in Microsoft Office applications, such as Microsoft Word and Microsoft Excel, that gives the user the ability to change the formatting of selected text.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>19", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Bola intends to - the synonym of a certain word during Word processing. What is the most appropriate tool to use?", "images": [], "options": {"A": "Assistance", "B": "Change case", "C": "Grammar checker", "D": "Thesaurus"}, "answer": "D", "explanation": "If Bola intends to find the synonym of a certain word during Word processing, the most appropriate tool to use is the Thesaurus. A Thesaurus in word processing is a software tool that is used to look up synonyms (words with similar meanings) and antonyms (words with opposite meanings) of a particular word. Assistance, Change case, and Grammar checker do not provide synonyms for words.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>20", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "In work sheet, which of the following actions would select Non-contiguous cells?", "images": [], "options": {"A": "Holding down Shift Key", "B": "Holding down Crtl Key", "C": "Holding down Alt Key", "D": "Holding down Crtl + Shift Key"}, "answer": "B", "explanation": "In a worksheet, non-contiguous cells can be selected by holding down the Ctrl key and clicking on the cells you want to select. This allows you to select multiple cells that are not next to each other. The Shift key is used to select a range of contiguous cells, and the Alt key does not have a function related to cell selection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>21", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Which of these formular would not b executed in MS Excel?", "images": [], "options": {"A": "=SUM(examscore)", "B": "=SUM(examscore)-12", "C": "=SUM(exam_score)*8", "D": "=SUM(exam score)/3"}, "answer": "D", "explanation": "In MS Excel, the formula '=SUM(exam score)/3' would not be executed because the space between 'exam' and 'score' is not allowed in cell references. Cell references should be one word, with no spaces. The correct formula would be '=SUM(exam_score)/3' if 'exam_score' is a named range or '=SUM(A1:A3)/3' if you are referring to specific cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>22", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "What are the most commonly used transmission speeds in BPS used in data communication?", "images": [], "options": {"A": "300", "B": "1200", "C": "2400", "D": "9600"}, "answer": "D", "explanation": "The most commonly used transmission speeds in BPS (bits per second) used in data communication are higher than the options provided. However, among the options, 9600 BPS is the highest and thus the most commonly used. Modern data communication systems often use much higher speeds, typically in the Mbps (megabits per second) or Gbps (gigabits per second) range.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>23", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "When a database recovery manager is invoked after a crash, restart proceeds in the following three phases:  I.  Undo  II.  Redo  III.  Analysis  Arrange these phases in the right order.", "images": [], "options": {"A": "I,II,III", "B": "II,I,III", "C": "III,II,I", "D": "I,III,II"}, "answer": "C", "explanation": "In the event of a crash, a database recovery manager follows these three phases in order: Analysis, Redo, and Undo. The Analysis phase identifies the transactions that were in progress at the time of the crash. The Redo phase re-applies all updates to ensure all changes by committed transactions are reflected. The Undo phase then rolls back the changes made by uncommitted transactions. Therefore, the correct order is III, II, I.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2017>24", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "During presentation,slide transition can be activated by", "images": [], "options": {"A": "Right-click", "B": "Mouse drag", "C": "Mouse click", "D": "Double-click"}, "answer": "C", "explanation": "During a presentation, slide transitions are typically activated by a mouse click. This is a common feature in presentation software like Microsoft PowerPoint, where a click of the mouse button advances to the next slide or triggers an animation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>25", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Planning and creating of website is called web", "images": [], "options": {"A": "analysis", "B": "design", "C": "maintenance", "D": "publishing"}, "answer": "B", "explanation": "Web design is the process of creating websites. It encompasses several different aspects, including webpage layout, content production, and graphic design. While the terms web design and web development are often used interchangeably, web design is technically a subset of the broader category of web development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>26", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Magazines and brochures can be produced using a", "images": [], "options": {"A": "Data processing software", "B": "Graphic software", "C": "Presentation software", "D": "Web authoring Software"}, "answer": "B", "explanation": "In computer graphics, graphics software refers to a program or collection of programs that enable a person to manipulate images or models visually on a computer. Computer graphics can be classified into distinct categories: raster graphics and vector graphics, with further 2D and 3d variants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>27", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Which of the following is one of the tools used to maintain the computer?", "images": [], "options": {"A": "Blower", "B": "Calliper", "C": "Cotton wool", "D": "Kerosine"}, "answer": "A", "explanation": "They are mainly used for flow of air/gas required for exhausting, aspirating, cooling, ventilating, conveying etc. Blower is also commonly known as Centrifugal Fans in industry.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>28", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Which of the following is not a good computer maintenance practice", "images": [], "options": {"A": "Blowing the system unit with a blower", "B": "Blowing the keyboard with a blower", "C": "Cleaning the screen with wet cloths", "D": "Cleaning the CD-ROM Drive with Lens cleaner"}, "answer": "C", "explanation": "Cleaning the screen with wet cloths is not a good computer maintenance practice. The moisture from the wet cloth can seep into the screen and cause damage. Instead, it is recommended to use a soft, dry cloth or a special screen cleaning solution to clean the computer screen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>29", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Commonly accept practices, rules and method in computing are called", "images": [], "options": {"A": "Conventions", "B": "Habits", "C": "Laws", "D": "Standards"}, "answer": "D", "explanation": "Standards in computing help ensure consistency, interoperability, and compatibility among hardware, software, and systems. These standards can cover various aspects of computing, including data formats, communication protocols, programming languages, and more.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>30", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Which of the following is a safety measure in the computer laboratory?", "images": [], "options": {"A": "eating in the compter laboratory", "B": "illumination in the computer laboratory", "C": "opening up the monitors by unauthorized persons", "D": "poor ventilation in the computer laboratory"}, "answer": "B", "explanation": "Among the options provided, 'illumination in the computer laboratory' is a safety measure. Proper lighting is essential in a computer laboratory to prevent eye strain and to ensure visibility. The other options are not safety measures. Eating in the computer lab can cause damage to the equipment, unauthorized persons opening up monitors can lead to electrical hazards, and poor ventilation can cause overheating of the equipment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>31", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Safety measures to be observed when using the computer includes all the following except", "images": [], "options": {"A": "Use of Anti-glare protector", "B": "Sitting posture", "C": "Maintaining a dust-free environment", "D": "Dropping liquids in the computer room"}, "answer": "D", "explanation": "All the options listed are safety measures to be observed when using a computer except for 'Dropping liquids in the computer room'. This is actually a hazard that can cause damage to the computer equipment and even lead to electrical shocks. Therefore, it is not a safety measure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>32", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Which of the following is not an advantage of wireless LAN?", "images": [], "options": {"A": "slower data transmission", "B": "higher error rate", "C": "interference of transmissions from different computers", "D": "all of the above"}, "answer": "D", "explanation": "Advantages of Wifi        Convenience. – The wireless nature of such networks allow users to access network resources from nearly any convenient location within their primary networking environment. ...      Mobility. ...      Productivity. ...      Deployment. ...      Expandability. ...      Cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>33", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Which of the following is not an non anti-virus?", "images": [], "options": {"A": "avast", "B": "avg", "C": "compaq", "D": "norton"}, "answer": "C", "explanation": "Compaq was a company founded in 1982 that developed, sold, and supported computers and related products and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>34", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Which of the following is used to restrive specific information from database tables?", "images": [], "options": {"A": "index", "B": "query", "C": "report", "D": "table"}, "answer": "B", "explanation": "Then the Database Management System (DBMS), software for managing databases, selects the demanded data from the database. The retrieved data may be stored in a file, printed, or viewed on the screen. A query language, such as Structured Query Language (SQL), is used to prepare the queries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>35", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Which of these methods would delete relationship defined between two tables in MS Access?", "images": [], "options": {"A": "Selecting delete relationship from the Edit menu dialogue box", "B": "Selecting the relationship line and pressing Delete key", "C": "Select Delete from the relationship menu", "D": "Selecting Delete relationship from the file drop down menu"}, "answer": "B", "explanation": "To remove a table relationship in a desktop database, you delete the relationship line in the Relationships window. Position the cursor so that it points to the relationship line, and then click the line. The relationship line appears thicker when it is selected. With the relationship line selected, press Delete.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>36", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Which of the following is not an effect of  computer virus? It", "images": [], "options": {"A": "distorts the computer screen", "B": "interfere with computer operation", "C": "damages the computer", "D": "corrupt the computer"}, "answer": "C", "explanation": "A computer virus is a malicious software program that can cause harm to a computer system by altering the way it operates or by accessing private information. However, it does not physically damage the computer hardware. It can distort the computer screen, interfere with computer operation, and corrupt the computer system by altering or deleting files.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2017>37", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "What file organization would require that all the five (5) records to be read before the 6th record is written?", "images": [], "options": {"A": "Direct access file", "B": "Index sequential file", "C": "Random access file", "D": "Sequential access file"}, "answer": "D", "explanation": "Sequential file organization    * Records are stored and accessed in a particular order sorted using a key field.  * Retrieval requires searching sequentially through the entire file record by record to the end.  * Because the record in a file are sorted in a particular order, better file searching methods like the binary search technique can be used to reduce the time used for searching a file .  * Since the records are sorted, it is possible to know in which half of the file a particular record being searched is located, Hence this method repeatedly divides the set of records in the file into two halves and searches only the half on which the records is found.  * For example, of the file has records with key fields 20, 30, 40, 50, 60 and the computer is searching for a record with key field 50, it starts at 40 upwards in its search, ignoring the first half of the set.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>38", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following is not an advantage of file organisation?", "images": [], "options": {"A": "Faster processing of data input", "B": "Post data retriever", "C": "Prevention of data failure and data loss", "D": "Safety of data information in storage medium"}, "answer": "C", "explanation": "records cannot support modern technologies that require fast access to stored records.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>39", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Maintaining the value and content of data is part of data", "images": [], "options": {"A": "coding", "B": "integrity", "C": "secrecy", "D": "security"}, "answer": "B", "explanation": "Data integrity is the maintenance of, and the assurance of the accuracy and consistency of, data over its entire life-cycle, and is a critical aspect to the design, implementation and usage of any system which stores, processes, or retrieves data", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2017>40", "subject": "Data Processing", "year": "2017", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Which of these of operations would not improve the performance of a parallel database system?", "images": [], "options": {"A": "Building indexes", "B": "Deleting unwanted data", "C": "Evaluating queries", "D": "Storing data across several sites"}, "answer": "D", "explanation": "A parallel database system seeks to improve performance through parallelization of various operations, such as loading data, building indexes and evaluating queries. Parallel databases improve processing and input/output speeds by using multiple CPUs and disks in parallel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>1", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The modern definition of a computing machine is based on a concept known as", "images": [], "options": {"A": "circuit switching.", "B": "digital circuit.", "C": "packet switching.", "D": "stored program."}, "answer": "D", "explanation": "The modern definition of a computing machine is based on a concept known as 'stored program'. This concept, also known as the von Neumann architecture, is a design model for a stored-program digital computer that uses a processing unit and a single separate storage structure to hold both instructions and data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>2", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Arrange the following ICT tools in the order of invention from the earliest to the latest:  cell phone, Internet, satellite and radio.", "images": [], "options": {"A": "Cell phone, satellite, radio, Internet", "B": "Internet, satellite, cell phone, radio", "C": "Radio, satellite, Internet, cell phone", "D": "Radio, cell phone, satellite, Internet"}, "answer": "D", "explanation": "Radio, cell phone, satellite and Internet. This is the arrangement of ICT tools in the order of invention from the earliest to the latest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>3", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The process of gathering facts and statistics from different sources is known as data", "images": [], "options": {"A": "analysis", "B": "collection", "C": "collation", "D": "retrieval"}, "answer": "B", "explanation": "The process of gathering facts and statistics from different sources is known as data collection. Data collection is the process of gathering and measuring information on variables of interest, in an established systematic fashion that enables one to answer stated research questions, test hypotheses, and evaluate outcomes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>4", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "A chart is a graphical representation of", "images": [], "options": {"A": "data", "B": "map", "C": "process", "D": "transmission"}, "answer": "A", "explanation": "A chart is a graphical representation of data or information. It is a diagram, picture or graph which is intended to make information easier to understand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>5", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The use of transistors in circuits was a major advancement in the", "images": [], "options": {"A": "first generation computers.", "B": "second generation computers.", "C": "third generation computers.", "D": "fourth generation computers."}, "answer": "B", "explanation": "Second Generation: Transistors (1956-1963)  The transistor was far superior to the vacuum tube, allowing computers to become smaller, faster, cheaper, more energy-efficient and more reliable than their first-generation predecessors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>6", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "An ICT-based service that uses telecommunication devices to hold meeting among many participants in two or more locations is known as", "images": [], "options": {"A": "broadcasting.", "B": "multimedia.", "C": "podcasting.", "D": "teleconference."}, "answer": "D", "explanation": "Teleconference is an ICT-based service that users telecommunication devices to hold meeting among many participants in two or more location.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>7", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of these devices does not support wireless communication?", "images": [], "options": {"A": "GSM phone", "B": "Mouse", "C": "Router", "D": "Telephone"}, "answer": "B", "explanation": "A mouse is an input device that is used to control the cursor on a computer screen. It is typically connected to the computer using a cable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>8", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The following hardware devices are used for output operations except", "images": [], "options": {"A": "monitor.", "B": "microphone.", "C": "plotter.", "D": "projector."}, "answer": "B", "explanation": "Microphone is an input device and not output device. Monitor, Plotter and projector are used for output operations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>9", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The manipulation of digitized information by computer or other digital electronic equipment is known as", "images": [], "options": {"A": "data collation.", "B": "data manipulation.", "C": "information manipulation.", "D": "information processing."}, "answer": "D", "explanation": "Information processing is the manipulation of digitalized information by computer or other digital electronic equipment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>10", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Which of the following statements explains information processing?", "images": [], "options": {"A": "Saving documents in a device", "B": "Changing information detectable by an observer", "C": "Data upload to server", "D": "Transfer of information between devices"}, "answer": "B", "explanation": "Information processing involves the change or manipulation of information in a way that makes it detectable or understandable by an observer. It does not merely involve saving documents, uploading data to a server, or transferring information between devices, but rather the transformation of this data into a meaningful format.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>11", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The information transmission medium from location A to location B in space is called", "images": [], "options": {"A": "asynchronous transmission.", "B": "guided transmission.", "C": "synchronous transmission.", "D": "wireless transmission."}, "answer": "D", "explanation": "The transmission of information from one location to another in space is typically done through wireless transmission. Asynchronous, guided, and synchronous transmissions are types of data transmission methods, but they do not specifically refer to the medium of transmission from one location to another in space.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>12", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "What is the role of the part labelled II in Figure 1?", "images": ["Data Processing/imgs/2019/img1.png"], "options": {"A": "Interpreter", "B": "Medium", "C": "Receiver", "D": "Source"}, "answer": "B", "explanation": "The role of the part labelled II in the diagram above is medium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>13", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Which of these technologies allows wireless connectivity in a Personal Area Network?", "images": [], "options": {"A": "Bandwidth", "B": "Bluetooth", "C": "Broadband", "D": "Satellite"}, "answer": "B", "explanation": "Bluetooth technology allows wireless connectivity in a Personal Area Network (PAN). A PAN is a network of devices used by an individual for personal or work-related tasks. Bluetooth enables these devices to connect and communicate wirelessly. Bandwidth refers to the data transfer capacity of a network, broadband is a high-speed internet connection, and satellite is a type of wireless transmission technology, but none of these specifically allow wireless connectivity in a PAN.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>14", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The main function of the device in the part labelled II in Figure 2 is", "images": ["Data Processing/imgs/2019/img2.png"], "options": {"A": "spending up the rate of data transfer to the part labelled I", "B": "providing services to the other devices in the setup", "C": "forwarding data packets between computers", "D": "controlling the access to the part labelled I"}, "answer": "C", "explanation": "The main function of the part labelled II in the diagram above is to forward data packets between computers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>15", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Use Figure 3 to answer this question      The title of the web page being accessed on the interface in Figure 3 is displayed on the part labelled", "images": ["Data Processing/imgs/2019/img3.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "The title of the web page being accessed on the interface in the diagram displayed on the part labelled II.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>16", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Use Figure 3 to answer this question    The shortcut key combination for adding a new tab in Figure 3 is", "images": ["Data Processing/imgs/2019/img3.png"], "options": {"A": "Alt + N", "B": "Alt + T", "C": "Ctrl + N", "D": "Ctrl + T"}, "answer": "C", "explanation": "The shortcut key combination for adding a new tab in the diagram above is Ctrl + N.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>17", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A program that enables the computer hardware to communicate and function effectively is", "images": [], "options": {"A": "translator", "B": "liveware", "C": "operating system", "D": "application software"}, "answer": "C", "explanation": "Operating system is a program that enables the computer hardware to communicate and function effectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>18", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A Word document can have any of these file extensions except", "images": [], "options": {"A": ".doc", "B": ".docx", "C": ".jpg", "D": ".rtf"}, "answer": "C", "explanation": ".jpg is a file extension for a graphics file format used in digital photography and web graphics. It is not a file extension for a Word document. Word documents typically have .doc or .docx extensions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>19", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "Which of the following command shortcuts can be used to display the dialog box in Figure 4 when the application is running?", "images": ["Data Processing/imgs/2019/img4.png"], "options": {"A": "Ctrl + O", "B": "Ctrl + S", "C": "Ctrl + Y", "D": "Ctrl + Z"}, "answer": "A", "explanation": "The command shortcuts that can be used to display the dialog box in the diagram above when the application is running is Ctrl + O.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>20", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The first step taken in editing a chart in MS Excel is", "images": [], "options": {"A": "click and drag the chart object.", "B": "click the chart object.", "C": "copy the chart object.", "D": "drag the chart object."}, "answer": "B", "explanation": "The first step in editing a chart in MS Excel is to click the chart object. This will activate the chart tools in the ribbon, which allows you to edit the chart.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>21", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "By default, numeric values in a worksheet are", "images": [], "options": {"A": "centered.", "B": "left-aligned.", "C": "right-aligned.", "D": "unaligned."}, "answer": "C", "explanation": "By default, numeric values in a worksheet are right-aligned. This is a standard convention in spreadsheet software like Microsoft Excel to help users easily distinguish numbers from text, which is typically left-aligned.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>22", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The diagram in Figure 5 depicts a", "images": ["Data Processing/imgs/2019/img5.png"], "options": {"A": "flat file database.", "B": "hierarchical database.", "C": "network database.", "D": "parallel database."}, "answer": "C", "explanation": "The diagram above in figure 5 depicts a network database.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>23", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Which of the following sets are available when creating a table in \"Design View\" in Microsoft Access?", "images": [], "options": {"A": "DataType, Description and Field Name", "B": "Description, Criteria and Field Property.", "C": "FieldName, DataType and Field Property", "D": "Criteria, FieldName and Description"}, "answer": "C", "explanation": "When creating a table in Design View in Microsoft Access, the following sets of properties are available:    Field Name: The name of the field.  Data Type: The type of data that the field will store.  Field Properties: Additional properties that control how the field is stored and displayed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>24", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "The MS Powerpoint feature which can be used to change the appearance of the entire presentation is the", "images": [], "options": {"A": "Add slide option.", "B": "Design template.", "C": "Online view.", "D": "Slide Layout option."}, "answer": "B", "explanation": "The MS powerpoint feature which can be used to change the appearance of the entire presentation is the design template.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>25", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "One example of web design package is", "images": [], "options": {"A": "MS FrontPage", "B": "MS Outlook", "C": "Peachtree", "D": "SPSS"}, "answer": "A", "explanation": "MS FrontPage is a web design package. It is a WYSIWYG (What You See Is What You Get) editor that allows users to create and edit web pages without knowing HTML. The other options are not web design packages. MS Outlook is an email client, Peachtree is an accounting software, and SPSS is a statistical analysis software.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>26", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The part labelled II in Figure 6 is used to", "images": ["Data Processing/imgs/2019/img6.png"], "options": {"A": "shape objects", "B": "select and transform objects", "C": "draw lines and curves", "D": "create texts"}, "answer": "A", "explanation": "The part labelled II in the diagram is used to shape object.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>27", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "In computer maintenance, the dampen material can be used on the following devices except", "images": [], "options": {"A": "DVD lens", "B": "keyboard", "C": "mouse", "D": "screen"}, "answer": "B", "explanation": "In computer maintenance, a dampen material should not be used on a keyboard. This is because the moisture from the dampen material can seep into the keyboard and cause damage to the electronic components. DVD lens, mouse, and screen can be cleaned with a dampen material, but it should be done carefully to avoid damage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>28", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Dust from the system unit casing can be removed using", "images": [], "options": {"A": "antistatic wipes.", "B": "cotton wool.", "C": "static wipes.", "D": "wet cloth."}, "answer": "A", "explanation": "Dust from the system unit casing can be removed using antistatic wipes. These wipes are designed to safely clean electronic equipment without causing static electricity, which can damage electronic components. Cotton wool, static wipes, and wet cloth are not recommended for cleaning the system unit casing as they can generate static electricity or cause moisture damage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>29", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Indiscriminate sending of unsolicited e-mails to many e-mail addresses is known as", "images": [], "options": {"A": "plagiarism", "B": "phishing", "C": "pharming", "D": "spamming"}, "answer": "D", "explanation": "Indiscriminate sending of unsolicited e-mails to many e-mail addresses is known as spamming. Spamming is the use of messaging systems to send an unsolicited message (spam) to large numbers of recipients for the purpose of commercial advertising, for the purpose of non-commercial proselytizing, or for any prohibited purpose (especially the fraudulent purpose of phishing).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>30", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "In computing, ergonomics is a term associated with computer", "images": [], "options": {"A": "ethics", "B": "maintenance", "C": "malware detection", "D": "safety measure"}, "answer": "D", "explanation": "The definition of computer ergonomics is the practice of fitting the set up of the computer and the workspace to fit the user and the user's work needs in order to minimize physical stress on the computer user.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>31", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "Where was Abacus invented?", "images": [], "options": {"A": "argentina", "B": "australia", "C": "china", "D": "united states of america"}, "answer": "C", "explanation": "The first Chinese Abacus was invented around 500 B.C. The Abacus, as we know it today, was used in China around 1300 A.D.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>32", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "Computer professional bodies in Nigeria include the following except", "images": [], "options": {"A": "Internet Service Providers Association of Nigeria.", "B": "Nigerian Computer Society.", "C": "Nigerian Information Technology Development Agency.", "D": "Nigeria Internet Group."}, "answer": "A", "explanation": "Internet Service Providers Association of Nigeria is not a computer professional bodies in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>33", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "The malware which appears as a harmless object but attacks its victims at the slightest opportunity is called", "images": [], "options": {"A": "worm.", "B": "trojan horse.", "C": "macro virus.", "D": "logic bomb."}, "answer": "B", "explanation": "The malware which appears as a harmless object but attacks its victims at the slightest opportunity is known as trojan horse.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2019>34", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Virus effect can be prevented by", "images": [], "options": {"A": "installing and updating antivirus.", "B": "installing new operating system.", "C": "purchasing new computer.", "D": "using external disks on public computer system."}, "answer": "A", "explanation": "Installing and updating antivirus software is a proven method to prevent virus effects. Antivirus software is specifically designed to detect, prevent, and remove malicious software like viruses. Regular updates are necessary to ensure the software can effectively combat the latest threats.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2019>35", "subject": "Data Processing", "year": "2019", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The part of the object in Figure 7 labelled II are called", "images": ["Data Processing/imgs/2019/img7.png"], "options": {"A": "attributes.", "B": "entitles.", "C": "models.", "D": "relations."}, "answer": "D", "explanation": "The part labelled in the diagram above are called Relations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>1", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The use of Visual Display Unit was a major breakthrough in the", "images": [], "options": {"A": "first generation computers", "B": "second generation computer", "C": "third generation computers", "D": "fifth generation computers"}, "answer": "C", "explanation": "BetwEen 1964-1971 which was the third generation of computer was characterized by further reduction in size of the VDu low cost.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>2", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "In hexadecimal system, D is equivalent to", "images": [], "options": {"A": "15", "B": "14", "C": "13", "D": "10"}, "answer": "C", "explanation": "In Hexadecimal numbering system, number from 0 to 9 are used while capital letters A to F represent its Binary or Decimal number equivalent,starting with the least significant digit at the right hand side.Therefore, A is 10, B is 11, C is 12, D is 13, E is 14 and F is 15.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>3", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "A teacher computed the average score of students in a given test.The result of the computation describes", "images": [], "options": {"A": "record", "B": "information", "C": "data", "D": "file"}, "answer": "B", "explanation": "The average score of students in a given test is a piece of information. In data processing, data refers to raw facts or figures that have not been processed. When these facts or figures are processed, they become information, which has more meaning than the raw data. Therefore, the result of the computation, which is the average score, is information because it has been processed from the raw test scores.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>4", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The sum of 110 and 101 in base two is", "images": [], "options": {"A": "1101 base 2", "B": "1110 base 2", "C": "1100 base 2", "D": "1011 base 2"}, "answer": "D", "explanation": "110                   +   101                         1011", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>5", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "One advantage of the first generation computer is", "images": [], "options": {"A": "processing speed", "B": "portability", "C": "heating effect", "D": "burglar-proof"}, "answer": "A", "explanation": "Advantages of first generation of computer are:  - More reliable  - Less heat generated  - Wider commercial use  - Better portability", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>6", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Magnetic Ink Character Recognition is applied on", "images": [], "options": {"A": "voice recognition devices", "B": "mobile devices", "C": "large data capturing machines", "D": "bank cheques"}, "answer": "D", "explanation": "Magnetic ink character recognition is a character recognition system that uses special ink and characters.When a document that contains this ink needs to be read,it passes through a machine,which magnetizez the ink and then translates the magnetic information into characters. MICR technology is used by banks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>7", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Internet banking entails", "images": [], "options": {"A": "applying computer networks in banking operations", "B": "applying computers to automatic banking operations", "C": "generating tokens and One-Time Passwords for online payment", "D": "using ATM for banking operations"}, "answer": "A", "explanation": "Internet banking is a quick and easy way to access the account through internet.It allows user to conduct financial transactions via the internet. A customer needs a device, an internet connection, and a bank card to register.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>8", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which of the following parts of the computer ensures the smooth operation of its hardware?", "images": [], "options": {"A": "Main memory", "B": "Control unit", "C": "Auxiliary storage", "D": "Arithmetic and Logical unit"}, "answer": "B", "explanation": "The Control Unit of a computer ensures the smooth operation of its hardware. It manages and coordinates all the hardware components of the computer system. It does not store data like the Main memory or Auxiliary storage, nor does it perform calculations like the Arithmetic and Logical unit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>9", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Basic computer operations include the following except", "images": [], "options": {"A": "control", "B": "input", "C": "output", "D": "process"}, "answer": "A", "explanation": "Control is not a basic computer operation. The basic operations of a computer are input (entering data), process (manipulating the data), and output (presenting the results). Control, on the other hand, is a function of the Control Unit, which manages and coordinates the operations of the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>10", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "One disadvantage of electronic data processing is", "images": [], "options": {"A": "handling complex computer", "B": "medium for effective storage", "C": "processing data at a phenominal", "D": "vulnerability to attack"}, "answer": "D", "explanation": "Disadvantages of electronic data processing  are:  - electronic form of data is susceptible to hacking attempt  - increases cyber crimes  - data are kept in encrpted form", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>11", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following sources of information is received by the user in visual mode only?", "images": [], "options": {"A": "Television", "B": "Radio", "C": "Photograph", "D": "Computer"}, "answer": "C", "explanation": "Some examples of primary source formats include:        archives and manuscript material.      photographs, audio recordings, video recordings, films.      journals, letters and diaries.      speeches.      scrapbooks.      published books, newspapers and magazine clippings published at the time.      government publications.      oral histories", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>12", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Which of the options A to D is not a medium of information transmission?", "images": [], "options": {"A": "Cable", "B": "Satellite", "C": "Television set", "D": "Wireless channels"}, "answer": "C", "explanation": "A television set is a device that receives and displays broadcast signals, but it does not transmit information itself. It is a receiver, not a transmitter.    The other options, cable, satellite, and wireless channels, are all mediums for transmitting information.    Cable television uses coaxial cables to transmit signals to homes and businesses. Satellite television uses satellites to transmit signals to earth. Wireless channels use radio waves to transmit signals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>13", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "A company has four computer systems, one printer and one scanner for its daily operations. One factor that can motivate the company to connect all the devices in a network is the need to", "images": [], "options": {"A": "provide efficient services", "B": "save running cost", "C": "share software only", "D": "use a wireless connection"}, "answer": "A", "explanation": "In an ideal world, efficient work means achieving maximum productivity with minimum wasted effort. When it comes to maximizing customer service productivity, streamlined customer interactions and cost-effective software are your best friends", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>14", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "One similarity between the internet and intranet is that they both", "images": [], "options": {"A": "were invented by the same company", "B": "use the same technology", "C": "have the same coverage", "D": "are open to the public"}, "answer": "B", "explanation": "Both the internet and intranet use the same underlying technology, which is the TCP/IP protocol suite. This technology allows for the transmission of data over networks. However, they differ in terms of accessibility and coverage. The internet is a global network that is accessible to the public, while an intranet is a private network accessible only to members of a particular organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>15", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The process of copying data or information from the internet to a personnel computer is termed", "images": [], "options": {"A": "browsing", "B": "downloading", "C": "retrieving", "D": "surfing"}, "answer": "B", "explanation": "Downloading means to receive data from a remote system,typically a server such as a web server, an FTP server, an email server, or other similar system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>16", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "An entrepreneur who wishes to send digital data over a telephone line would need a", "images": [], "options": {"A": "hub", "B": "modem", "C": "router", "D": "switch"}, "answer": "B", "explanation": "A modem – a portmanteau of \"modulator-demodulator\" – is a hardware device that converts data from a digital format, intended for communication directly between devices with specialized wiring, into one suitable for a transmission medium such as telephone lines or radio", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>17", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "Graphical User Interface is considered user friendly because of the following reasons except that all", "images": [], "options": {"A": "compels the user to leave all the command before operating the system", "B": "displaying all the options available in the acess", "C": "is easier for users to operate and understand", "D": "makes the icons and menu familiar to the user"}, "answer": "A", "explanation": "Graphical user interface is a visual way of interacting with a computer using items such as windows, icons, and menus, used by most modern operating systems. It allows users to interact with electronic devices through graphical icons and audio indicator such as primary notation, instead of text-based user interface,typed command and labels or text navigation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>18", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The symbols dialog box of MS word application is located on the", "images": [], "options": {"A": "Format menu", "B": "Help menu", "C": "Insert menu", "D": "View menu"}, "answer": "C", "explanation": "The symbols dialog box of MS Word application is located on the Insert menu. From the Insert menu, you can select 'Symbol' to open the symbols dialog box.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>19", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Pressing the key combination Ctrl + J on a selected text in a Microsoft Word document world", "images": [], "options": {"A": "align the text", "B": "deselect the text", "C": "justify the paragraph", "D": "juxtapose the text"}, "answer": "C", "explanation": "In Microsoft Word, the key combination Ctrl + J is used to justify the paragraph. Justifying a paragraph aligns the text with both the left and right margins, adding extra space between words as necessary. This gives your text a clean, squared-off look.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>20", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The Merge button in Spreadsheet application is used to", "images": [], "options": {"A": "combine adjacent tables", "B": "convert selected cells into a single cell", "C": "merge two tables", "D": "split a cell into two or more cells"}, "answer": "B", "explanation": "Merge cell is a function in database programming that enables different nearby cells to be joined into a single larger cell.    This document explains how to merge cells within all versions of Microsoft Excel. Merging cells is often used when a title is to be centered over a particular section of a spreadsheet. When a group of cells is merged, only the text in the upper-leftmost box is preserved.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>21", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "If cell A20 in MS Excel contains the value 5, then the formula \"A20*3\" will return a value equal to", "images": [], "options": {"A": "15", "B": "25", "C": "75", "D": "125"}, "answer": "A", "explanation": "In MS Excel, the formula \"A20*3\" multiplies the value in cell A20 by 3. If cell A20 contains the value 5, then the formula will return 15 (5*3).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>22", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "A database contains list of customers and their phone numbers.What type of relationship describes a computer having multiple phone numbers?", "images": [], "options": {"A": "Many-to-many", "B": "Many-to-one", "C": "One-to-many", "D": "One-to-one"}, "answer": "C", "explanation": "In system analysis, a one-to-many relationship is a type of cardinality that refers to the relationship between two entities A and B in which an element of A may be linked to many elements of B, but a member of B is linked to only one element of A.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>23", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "table Marksheet  IDNAMESCOREGRADE001Abdul55C002Emeka52C003Kola49P    The DBMS statement,select * from Marketsheet in table Marketsheet will display all records in the fields:", "images": [], "options": {"A": "ID and Name only", "B": "ID, Score and Grade only", "C": "Score and Grade only", "D": "ID, Name, Score and Grade"}, "answer": "D", "explanation": "A database management system is software for creating and managing database.It ensure that data is consistently organized and remains easily accessible.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>24", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Which of the following objects is not located on the slide Layout tab?", "images": [], "options": {"A": "Animations", "B": "Charts", "C": "Lists", "D": "Titles"}, "answer": "A", "explanation": "A slide layout is an arrangement of placeholder which are designed to help you position your slide content. A slide layout will contain placeholder for particular objects e.g text, charts, clipart, graphics, pictures, tables, videos, and sound", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>25", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "The following programming tools are employed by a web developer except", "images": [], "options": {"A": "COBOL", "B": "CSS", "C": "HTML", "D": "PHP"}, "answer": "A", "explanation": "COBOL (Common Business-Oriented Language) is a high-level programming language for business applications. It is not typically used in web development. Web development usually involves languages like HTML (HyperText Markup Language) for structuring content, CSS (Cascading Style Sheets) for styling, and PHP (Hypertext Preprocessor) for server-side scripting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>26", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "Graphics can be categorized using the following devices except", "images": [], "options": {"A": "webcam", "B": "scanners", "C": "joystick", "D": "digital camera"}, "answer": "C", "explanation": "A joystick is an input device commonly used for video games, and not a device for categorizing graphics. A webcam, scanner, and digital camera are all devices that can be used to create or capture graphics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>27", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Which of the following substances is used for cleaning the mouse ball?", "images": [], "options": {"A": "Distilled water", "B": "Engine oil", "C": "Isopropyl alcohol", "D": "Kerosene"}, "answer": "C", "explanation": "Usually a paperclip will do, but if it's really dirty you can use a knife or you can moisten the tip of a Q-tip (cotton swab) with rubbing alcohol to clean off the dirt.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>28", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "One characteristic of a dirty mouse is that the mouse", "images": [], "options": {"A": "is not recognized by the system", "B": "unmounts itself from the system", "C": "pointer changes appearance", "D": "pointer moves drastically"}, "answer": "D", "explanation": "A dirty mouse is characterized by erratic or uncontrolled movement of the pointer, which is caused by the accumulation of dirt or dust in the mouse. This is why the pointer moves drastically. The other options are incorrect because they do not describe the characteristics of a dirty mouse.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>29", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "One responsible way of using the computer is", "images": [], "options": {"A": "software piracy", "B": "publishing", "C": "pharming", "D": "ethical backing"}, "answer": "D", "explanation": "Ethical backing is the practice of using computers in a way that is consistent with ethical principles. This includes respecting the privacy of others, avoiding plagiarism, and not engaging in activities that could harm others.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>30", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Any activity carried out to to protect the user from hazards while using the computer is called", "images": [], "options": {"A": "computer ethics", "B": "computer maintenance", "C": "laboratory rules", "D": "safety measure"}, "answer": "D", "explanation": "Safety measures are activities and precautions taken to improve safety for overall health of the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>31", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "In order to protect a computer on the world wide web from threats, the user should", "images": [], "options": {"A": "install the latest operating system version", "B": "install a single user antivirus software", "C": "implement an internet security software", "D": "deploy online transaction applications"}, "answer": "C", "explanation": "To protect a computer on the world wide web from threats, the user should implement an internet security software. Internet security software provides protection against various online threats such as viruses, malware, spyware, and phishing attacks. It is more comprehensive than a single user antivirus software as it also includes features like firewall, email protection, and anti-phishing, which are not typically found in basic antivirus software.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>32", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Responsibilities of a database administrator include the following except performing", "images": [], "options": {"A": "database backup", "B": "data recovery", "C": "network maintenance", "D": "user authentication"}, "answer": "C", "explanation": "Database administrators use specialized software to store and organize data. The role may include capacity planning, installation,configuration,database design,migration, performance monitoring, security,troubleshooting as well as backup and data recovery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>33", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "The following tools are used for protecting the computer against virus attack except", "images": [], "options": {"A": "Avant anti malware", "B": "Kaspersky", "C": "Nortoes", "D": "Trojan horse"}, "answer": "D", "explanation": "Security tools to protect the computer are; Avant anti virus, zone alarm, ad-Aware, Spybot search and destroy, Hijackthis, Microsoft safety scanner, Firewalls etc", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>34", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Which of the following software replicates itself without being executed by the users?", "images": [], "options": {"A": "Worm", "B": "Trojan", "C": "Plug-ins", "D": "Driver"}, "answer": "A", "explanation": "Computer worm is a standalone malware computer program that replicates itself in order to spread to other computers.It often uses a computer network to spread itself,relying on securtiy failures on the target computer to access it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>35", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "In the model:  Furniture (Table, Chair, Wardrobe),  Furniture is", "images": [], "options": {"A": "a relation", "B": "a schema", "C": "a tuple", "D": "an attribute"}, "answer": "B", "explanation": "In the given model, Furniture (Table, Chair, Wardrobe), Furniture is a schema. A schema in a database system is a description of the structure of the database. It defines tables, fields, relationships, views, indexes, procedures, functions, queues, triggers, types, sequences, materialized views, synonyms, database links, directories, XML schemas, and other elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>36", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Which of the following database operations does not require a Data Manipulation Language?", "images": [], "options": {"A": "Modification of information", "B": "Insertion of new information", "C": "Deletion of information", "D": "Creation of information"}, "answer": "D", "explanation": "Data manipulation language(DML) statements or commands are used for managing data within tables. A data manipulation language is a computer programming language used for adding(inserting), deleting and modifying(updating) data in a database.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2020>37", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The file organization method which allows records to be accessed in any sequence is", "images": [], "options": {"A": "index", "B": "random", "C": "sequential", "D": "serial"}, "answer": "B", "explanation": "The file organization method which allows records to be accessed in any sequence is known as random file organization. In random file organization, records are stored in such a way that they can be accessed in any order, not just sequentially. This is achieved by using a unique key for each record, which is used to calculate the storage location of the record.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>38", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "A file organization that has reference which identifies a record in relation to other records is called", "images": [], "options": {"A": "indexed file organization", "B": "random file organization", "C": "sequential file organization", "D": "serial file organization"}, "answer": "A", "explanation": "Indexed-sequential file organization method is similar to sequential method only that, an index is used to enable the computer to locate individual records on the storage media.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>39", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Providing access control to a school record is the responsibility of a", "images": [], "options": {"A": "database administrator", "B": "programmer", "C": "systems administrator", "D": "system analyst"}, "answer": "A", "explanation": "Database administrator is a person who manages, use specialized software to store and organize data.The role may include capacity planning, installation, configuration,database design, migration,perfromance,security,trobleshooting,as well as backup and data recovery", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2020>40", "subject": "Data Processing", "year": "2020", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Figure 1 depicts", "images": ["Data Processing/imgs/2020/sscedata2020obj40.png"], "options": {"A": "a distributed database", "B": "a parallel database", "C": "an extranet", "D": "an intranet"}, "answer": "A", "explanation": "A distributed database is a database in which data is stored across different physical locations.It may be stored in multiple computers located in the same physical location or maybe dispersed over a network of interconnected computers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2021>1", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "The main component of the first generation computer was", "images": [], "options": {"A": "microchip", "B": "transistor", "C": "integrated circuit", "D": "electronic valve"}, "answer": "D", "explanation": "The main component of the first generation computer was vacuum tubes, also known as electronic valves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>2", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The number 101100101 base two in denary is", "images": [], "options": {"A": "753", "B": "653", "C": "357", "D": "356"}, "answer": "C", "explanation": "101100101 base two in denary   = 1 x 28 + 0 x 2 7 + 1 x 26 + 1 x 2 5 + 0 x 24 + 0 x 23 + 1 x 22 + 0 x 21 + 1 x 20   = 1 x 256 + 0 x 128 + 1 x 64 + 1 x 32 + 0 x 16 + 0 x 8 + 1 x 4 + 0 x 2 + 1 x 1   = 256 + 0 + 64 +32 + 0 +0 +4 + 0 + 1   = 35710", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>3", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The term Garbage-In-Garbage-Out is used to explain the characteristics of the computer in terms of", "images": [], "options": {"A": "storage", "B": "speed", "C": "power", "D": "accuracy"}, "answer": "D", "explanation": "In computer, garbage in, garbage out(GIGO) is the concept that flawed, or nonsense (garbage) input data produces nonsense output.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>4", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following statements is true?", "images": [], "options": {"A": "Data leads to information and information leads to knowledge", "B": "Data leads to knowledge and knowledge leads to information", "C": "Information leads to data and data leads to knowledge", "D": "Knowledge leads to information and information leads to data"}, "answer": "A", "explanation": "Whenever raw data are wrapped with meaning , those data become information. However, only relevant information leads to knowledge and non-relevant information does not lead to knowledge. Data transforms into information by assigning a meaning or context to date. The moment the information is processed, linked and stored, whether by machine or a human being, it becomes knowledge.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>5", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The type of computer that counts in discrete form only is referred to as", "images": [], "options": {"A": "analog computer", "B": "digital computer", "C": "hybrid computer", "D": "mainframe computer"}, "answer": "B", "explanation": "Digital computer, any of a class of devices capable of solving problems by processing information in discrete form. It operates on data, including magnitudes, letters and symbols that are expresses in binary code.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>6", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which of the following media involves point-to-point communication?", "images": [], "options": {"A": "Radio", "B": "Satellite", "C": "Telephone", "D": "Television"}, "answer": "C", "explanation": "The term point-to-point telecommunications means a wireless data link between two fixed points. The telecommunications signal is typically bi-directional and either time division multiple access or channelized e.g. telephone call.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>7", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "Fourth generation computer application can execute the following operations except", "images": [], "options": {"A": "digging of drainages", "B": "drainage channel design", "C": "management of recreational facilities", "D": "payroll management"}, "answer": "A", "explanation": "The 4GL may include support for database management, report generation, mathematical optimization, GUI development, or web development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>8", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The joystick is mainly used for", "images": [], "options": {"A": "clicking on links on web pages", "B": "drawings and playing computer games", "C": "erasing of unwanted graphics", "D": "typing of document in a word processors"}, "answer": "B", "explanation": "A joystick is a cursor control device used in computer games and assistive technology. Often used to control video games and usually have one or more push-buttons whose state can also be read by the computer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>9", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The manipulation of digitalized information by computer or other electronic equipment is known as", "images": [], "options": {"A": "data collation", "B": "data manipulation", "C": "information manipulation", "D": "information processing"}, "answer": "D", "explanation": "Information processing refers to the manipulation of digitized information by computers and other digital electronic equipment, known collectively as information technology(IT)", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>10", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Which of the following actions is not a source of computer virus?", "images": [], "options": {"A": "Checking of e-mail", "B": "Downloading programs", "C": "Reading from CD/DVD", "D": "Uploading data"}, "answer": "D", "explanation": "The sources of computer virus are:   - through internet   - Through Email   - Removable storage   - Bluetooth", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>11", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "When information is conveyed from one space to another, it is referred to as information", "images": [], "options": {"A": "retrieval", "B": "translation", "C": "transmission", "D": "transportation"}, "answer": "C", "explanation": "Information transmission can be referred to as the various ways or more of spending or passing information from one place to another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>12", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which of the following file organizations requires primary key?", "images": [], "options": {"A": "Indexed file organization", "B": "Random file organization", "C": "Serial file organization", "D": "Sequential file organization"}, "answer": "A", "explanation": "Indexed file organization is the storage of records in a file in sequence according to a primary key value.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>13", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The protocol for transferring files from one machine to another is", "images": [], "options": {"A": "SNMP", "B": "SMTP", "C": "FTP", "D": "FAT"}, "answer": "C", "explanation": "FTP (File Transfer Protocol) is a network protocol for transmitting files between computers over Transmission Control Protocol/Internet Protocol (TCP/IP) connections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>14", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Mr. Francis has an office complex with 20 rooms. What type of network is suitable for connecting all the computers in their various rooms into a single network?", "images": [], "options": {"A": "LAN", "B": "MAN", "C": "PAN", "D": "WAN"}, "answer": "A", "explanation": "Local Area Network(LAN) connect groups of computer and low-voltage devices together across short distances (within a building or between a group of two or three buildings in close proximity to each other) to share information and resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>15", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "The following software are web browsers except", "images": [], "options": {"A": "Firefox", "B": "Google Chrome", "C": "Linux", "D": "Opera"}, "answer": "C", "explanation": "Examples of software web browser are; Google Chrome, Mozilla Fire fox, Microsoft Internet Explorer, Apple Safari, Opera browser , Brave, Vivaldi etc", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>16", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "To visit the previous page using the interface in the diagram, the user will click on the part labeled", "images": ["Data Processing/imgs/2021/dataobjq16.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "B", "explanation": "The back button is a user interface feature that takes a user back to their previous location. For instance, in an internet browser, clicking the back button takes you back to the last web page you visited. The back button only works if there is a previous page in your browser history. The shortcut key combination for the back button is Alt + Left arrow key. Also backspace key works in many browser to go back.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>17", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "An operating system that enables more than one user to access the same data is called", "images": [], "options": {"A": "multi-tasking OS", "B": "multi-user OS", "C": "single user OS", "D": "virtual memory OS"}, "answer": "B", "explanation": "A multi-user operating system allows to permission of multiple users from accessing the single machine at a time. These servers grant the permission of multiple users to accessing the operating system, kernel and hardware simultaneously.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>18", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The feature of a word document that shows the page, number of words and errors found in a document is the", "images": [], "options": {"A": "menu bar", "B": "scroll bar", "C": "status bar", "D": "title bar"}, "answer": "C", "explanation": "A status bar is located at the bottom of internet browser windows and many application windows and displays the current state of the web page or application being displayed. In the early versions of internet Explorer, it showed whether the page was secure, its certificate, what loaded, and web address.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>19", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Diagram below shows a dialog box from Microsoft Word application. Use it to answer question below.          which of the following command shortcuts can be used to display the dialog box in the diagram when the application is running?", "images": ["Data Processing/imgs/2021/dataobjq19.png"], "options": {"A": "Ctrl+ O", "B": "Ctrl+ S", "C": "Ctrl+ Y", "D": "Ctrl +Z"}, "answer": "B", "explanation": "Ctrl+ S is a short key often used to save changes to a file.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>20", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Table below is an excerpt of a company's sales record on an MS Excel worksheet.    ABCDEFGH1STAFFDAYSITEM 1 SALES(#) ITEM 2 SALES(#) ITEM 3 SALES(#) ITEM 4 SALES(#) ITEM 5 SALES(#) ITEM 6 SALES(#)2 JOYMON2003005004003001503 AKINTUE 3002006004002002004 KEN WED 400 300 4005001003005                                                                               Figure 3    The highest sale by Joy is recorded in cell", "images": [], "options": {"A": "F1", "B": "B4", "C": "H3", "D": "E2"}, "answer": "D", "explanation": "Looking at the table, Joy's sales are recorded in row 2. The highest sale by Joy is 500, which is recorded in cell E2. Therefore, the correct answer is E2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>21", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The formula to calculate the average of a given range of data from cell B2 to cell D4 in a Microsoft Excel worksheet is", "images": [], "options": {"A": "= AVERAGE (B2+D4)", "B": "= AVERAGE(B2: D4)", "C": "= AVERAGE(B2,D4)", "D": "= AVERAGE (B2; D4)"}, "answer": "B", "explanation": "The correct formula to calculate the average of a given range of data from cell B2 to cell D4 in a Microsoft Excel worksheet is '= AVERAGE(B2: D4)'. The colon (:) in Excel formula represents a range. So, B2:D4 represents all cells between B2 and D4 inclusive.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>22", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The field in a database which uniquely identifies each record is called a", "images": [], "options": {"A": "composite key", "B": "foreign key", "C": "local key", "D": "primary key"}, "answer": "D", "explanation": "Primary key is a field containing a value that uniquely identifies each record in a table. The primary key is unique and prevents entering duplicate records or a null value in that field. The relationship is created only if the related field is the primary key in Table A and a foreign key in Table B.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>23", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The correct order of the steps taken in creating a database from the database template in MS Access 2007 is", "images": [], "options": {"A": "click on the Office button - click New-choose a database of your choice", "B": "click New - click on Office button - choose a database of your choice", "C": "click on database of your choice - click New- click on the Office button", "D": "click New - choose database of your choice - click on Office button"}, "answer": "A", "explanation": "The correct order of the steps taken in creating a database from the database template in MS Access 2007 is 'click on the Office button - click New-choose a database of your choice'. This is the standard procedure for creating a new database in MS Access 2007.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>24", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "To show the whole presentation in Microsoft Power Point 2007, select slide show from the", "images": [], "options": {"A": "design tab", "B": "home tab", "C": "title bar", "D": "menu bar"}, "answer": "D", "explanation": "To start your slide show, on the slide show tab, select play from beginning i.e. from the slide show menu choose view show option.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>25", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Web design package include the following except", "images": [], "options": {"A": "Macromedia Dreamweaver", "B": "iWeb", "C": "Front Page", "D": "Adobe PageMaker"}, "answer": "D", "explanation": "Web design packages are: Adobe dreamweaver, Google web designers, Microsoft sharePoint designer, Net objects fusion, Xara Web designers, etc", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>26", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The above diagram shows CorelDraw tool bar. The part labeled I is used to", "images": ["Data Processing/imgs/2021/dataobjq26.png"], "options": {"A": "shape objects", "B": "select objects", "C": "draw lines and curves", "D": "create texts"}, "answer": "B", "explanation": "The arrow shapes is used by selecting common shapes from the toolbox.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>27", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "One precautionary measure taken when cleaning a monitor is", "images": [], "options": {"A": "plugging of power supply cable", "B": "spraying a windows cleaner on the monitor", "C": "unplugging the power supply cable", "D": "using a vacuum cleaner to clean the monitor casing"}, "answer": "C", "explanation": "The measures taken are:   - never spray cleaning liquids directly unto any part of your computer   - do not spray canned compressed air with the can upside down   - do not touch  internal CPU component without wearing an anti-static wrist band or using an anti-static mat   - do not use a standard vacuum to clean inside of your computer etc", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>28", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The erratic movement of the mouse pointer is usually caused by", "images": [], "options": {"A": "damaged driver", "B": "dirty mouse ball", "C": "improper connection of mouse cable", "D": "outdated driver"}, "answer": "B", "explanation": "The erratic movement of the mouse pointer is usually caused by a dirty mouse ball. The mouse ball is a part of the mouse that comes into direct contact with the surface on which the mouse is used. If the mouse ball is dirty, it can cause the mouse pointer to move erratically. This is because the sensors inside the mouse that track the movement of the ball can become confused by the dirt, causing them to send incorrect signals to the computer about the mouse's movement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>29", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The use of the internet to perform illegal activities is generally called", "images": [], "options": {"A": "cyber crime", "B": "packet sniffling", "C": "phishing", "D": "spamming"}, "answer": "A", "explanation": "Cybercrime also called computer crime is the use of a computer as an instrument to further illegal ends, such as committing fraud, trafficking in child, pornography and intellectual property stealing identities, or violating privacy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>30", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "One safety measure to consider in a computer room is", "images": [], "options": {"A": "arranging the chairs in the room together", "B": "keeping liquid within the room", "C": "closing the door always", "D": "maintaining a dust -free environment"}, "answer": "D", "explanation": "- Clean up your work area before you leave   - Surf safely   - No food or drinks near the computers   - do not change computer settings or background etc", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>31", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Security breaches in computing cannot be prevented through the use of", "images": [], "options": {"A": "antivirus", "B": "encryption", "C": "firewall", "D": "firmware"}, "answer": "D", "explanation": "Firmware is a type of software that provides control, monitoring and data manipulation of engineered products and systems. It is typically embedded within the hardware of our computer system. While it's crucial for the functioning of the system, it doesn't prevent security breaches. Antivirus, encryption, and firewall are all tools used to prevent security breaches.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2021>32", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "A system analyst is a person who", "images": [], "options": {"A": "designs flowchart", "B": "designs and implements new solutions", "C": "trains computer users", "D": "writes complex computer programs"}, "answer": "B", "explanation": "A system analyst also known as business technology analyst is an information technology (IT) professional who specializes in analyzing, designing and implementing information systems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>33", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "The malware which is programmed to initiate at a specific date or when a specific event occurs is called", "images": [], "options": {"A": "directory virus", "B": "logic bomb", "C": "polymorphic virus", "D": "root kit virus"}, "answer": "B", "explanation": "A logic bomb is a malicious program that is triggered when a logical condition is met, such as after a number of transactions have been processed, or on a specific date (also called a time bomb).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>34", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "One advantage of information processing is that", "images": [], "options": {"A": "face-to-face interaction among staff may be reduced", "B": "initial investment cost can be high", "C": "running cost becomes lower in the long run", "D": "it encourage the training/retraining of staff"}, "answer": "C", "explanation": "Information processing can help to reduce running costs in the long run. This is because once the system is set up, the cost of processing each unit of information decreases. This is due to economies of scale and the fact that automated systems can process information more quickly and accurately than humans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>35", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The function of the SQL statement SELECT student ID, Surname, House Name FROM Student; is that", "images": [], "options": {"A": "retrieves the listed fields from student table", "B": "highlights the listed fields from student table", "C": "hides the selected fields from student table", "D": "deletes the listed fields from student table"}, "answer": "A", "explanation": "The function of the SQL statement SELECT student ID, Surname, HouseName FROM Student; is that it retrieves the listed fields from student table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>36", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The best arrangement that gives the correct order of magnitude of the database element is", "images": [], "options": {"A": "character, field, record, table, database, file", "B": "character, field, record, table, file, database", "C": "record, file, field, table, character, database", "D": "table, file, record, field, character, database"}, "answer": "B", "explanation": "The elements of a Database are:   - The database scheme   - Schema objects   - Indexes   - Tables   - Fields and column   - Records and rows   - Keys   _ Relationship   - Data types", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>37", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "A file organization that contains a reference number is called", "images": [], "options": {"A": "direct access", "B": "indexed access", "C": "random access", "D": "sequential access"}, "answer": "B", "explanation": "Indexed file is a computer file with an index that allows easy random access to any record given its file key.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2021>38", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The following media are used for information transmission except", "images": [], "options": {"A": "diary", "B": "magazine", "C": "radio", "D": "television"}, "answer": "A", "explanation": "A diary is not a medium used for information transmission. It is a personal record of experiences and observations. On the other hand, magazines, radios, and televisions are all media used for transmitting information to a wide audience.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>39", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "To prevent the loss of data in the computer, it is better to implement file", "images": [], "options": {"A": "access", "B": "maintenance", "C": "checks", "D": "backup"}, "answer": "D", "explanation": "A backup or data backup is a copy of computer data taken and stored elsewhere so that it may be used to restore the original after a data loss event.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2021>40", "subject": "Data Processing", "year": "2021", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Which of the following terms is not a feature of distributed database?", "images": [], "options": {"A": "Fragmentation", "B": "Multiple storage", "C": "Replication", "D": "Single server"}, "answer": "D", "explanation": "feature of distributed database are:   - location independent   - distributed query processing   - distributed transaction management   - hardware independent   - operating system independent   - network independent   - transaction transparency   - DBMS independent", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>1", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The concept of stored program for electronic devices was introduced by", "images": [], "options": {"A": "Ada Augusta Lovelace", "B": "Charles Babbage Lee", "C": "John Von Neumann", "D": "Tim Berners Lee"}, "answer": "C", "explanation": "The idea was introduced in the late 1940s by John von Neumann, who proposed that a program be electronically stored in binary-number format in a memory device so that instructions could be modified by the computer as determined by intermediate computational results.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>2", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "High level programming languages such as COBOL and FORTRAN were first used in the", "images": [], "options": {"A": "First generation computers", "B": "Second generation computers", "C": "Third generation computers", "D": "Fourth generation computers"}, "answer": "C", "explanation": "Third generation computers were computers that emerged due to the development of the integrated circuit (IC). They were the first steps toward computers as we know them today.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>3", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Any meaningful fact and knowledge item that can be expressed in words and numbers is called", "images": [], "options": {"A": "Data", "B": "Database", "C": "Information", "D": "Knowledge base"}, "answer": "C", "explanation": "Information is organized or classified data, which has some meaningful values for the receiver.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>4", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "At what stage in data processing does data manipulation take place?", "images": [], "options": {"A": "Organization", "B": "Interpretation", "C": "Collation", "D": "Analysis"}, "answer": "D", "explanation": "Data manipulation takes place at the analysis stage in data processing. Data manipulation is the process of changing data to make it easier to read or be more organized. Two common types of data manipulation are sorting and filtering. The analysis stage involves exploring and analyzing large amounts of data to discover meaningful patterns, trends, and relationships among the data. It is at this stage that data manipulation techniques are applied to clean and organize the data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>5", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The category of computers used for weather forecasting is known as", "images": [], "options": {"A": "General purpose computers", "B": "Microcomputers", "C": "Special purpose computers", "D": "Super computers"}, "answer": "D", "explanation": "A supercomputer is a computer with a high level of performance as compared to a general-purpose computer, they are used for a speciffic purpose.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>6", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "One application of ICT in education is", "images": [], "options": {"A": "Automated Teller Machine", "B": "Electronic Fund Transfer", "C": "Magnetic Ink Character Recognition", "D": "Optical Mark Reader"}, "answer": "D", "explanation": "Optical Mark reading (OMR) is a method of entering data into a computer system. Optical Mark Readers reads pencil or pen marks made in pre-defined positions on paper forms as responses to questions or tick list prompts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>7", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "An application of ICT which allows a person to participate in a meeting from a remote location is called", "images": [], "options": {"A": "Blogging", "B": "Broadcasting", "C": "Podcasting", "D": "Telepresence"}, "answer": "D", "explanation": "Telepresence refers to technologies that allow a user appear to be present, feel like they are present or have some effect in a space the person does not physically inhabit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>8", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The subdivision of tracks in a hard disk is called", "images": [], "options": {"A": "Cluster", "B": "Record", "C": "Row", "D": "Sector"}, "answer": "D", "explanation": "In computer disk storage, a sector is a subdivision of a track on a magnetic disk or optical disc. Each sector stores a fixed amount of user-accessible data, traditionally 512 bytes for hard disk drives (HDDs) and 2048 bytes for CD-ROMs and DVD-ROMs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>9", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The standard way of arranging information is known as", "images": [], "options": {"A": "Classification of information", "B": "Collection of information", "C": "Organization of information", "D": "Validation of information"}, "answer": "C", "explanation": "The standard way of arranging information is known as the organization of information. This involves structuring or arranging data in a particular or prescribed manner. The other options do not accurately describe the standard way of arranging information.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>10", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "One disadvantage of using computer for information processing is", "images": [], "options": {"A": "Low productivity", "B": "Reduced running cost in the long term", "C": "The increase in processing speed", "D": "The need for staff retraining"}, "answer": "D", "explanation": "One disadvantage of using a computer for information processing is the need for staff retraining. This is because as technology evolves, staff members need to be trained to use new systems and software. The other options are generally considered advantages of using computers for information processing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>11", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The process of sending and receiving information from one place to another is called information", "images": [], "options": {"A": "Technology", "B": "Transfer", "C": "Transmission", "D": "Synchronization"}, "answer": "C", "explanation": "Information transmission refers to the process of transferring information between two or more digital devices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>12", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The capacity of a communication channel is referred to as", "images": [], "options": {"A": "Bandwidth", "B": "Baud rate", "C": "Bit flow", "D": "Data flow"}, "answer": "A", "explanation": "Bandwidth is the volume of information that can be sent over a connection in a measured amount of time – calculated in megabits per second (Mbps).", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>13", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "The type of network which has a restricted coverage within an enterprise is called", "images": [], "options": {"A": "Internet", "B": "Intranet", "C": "Ethernet", "D": "Extranet"}, "answer": "B", "explanation": "Intranet is a local or restricted communications network, especially a private network created using World Wide Web software.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>14", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "One of the major differences between WAN and MAN is that", "images": [], "options": {"A": "WAN used routers while MAN uses switches", "B": "WAN connects countries while MAN connects continents", "C": "WAN has no limited coverage while MAN has limited coverage", "D": "WAN incorporate servers while MAN does not incorporate servers"}, "answer": "C", "explanation": "WAN has no limited coverage while MAN has limited coverage  The transmission speed of MAN is faster than WAN.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>15", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "To search for information using the interface in Figure 1, the key words of the search subject is typed into part labelled", "images": ["Data Processing/imgs/2022/dataprocessingq15.jpg"], "options": {"A": "I", "B": "II", "C": "IV", "D": "V"}, "answer": "C", "explanation": "In Figure 1, the designated area labeled 'IV' serves as the search box, where users can enter the relevant keywords or phrases to initiate a search for information. This search box is an essential component of the interface, facilitating efficient and effective information retrieval.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>16", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "To access a website, the URL of the website is typed into the part labelled", "images": ["Data Processing/imgs/2022/dataprocessingq15.jpg"], "options": {"A": "I", "B": "II", "C": "III", "D": "V"}, "answer": "C", "explanation": "The area labeled 'III' in the diagram represents the URL space, where users can enter the web address (URL) of the website they wish to visit. This URL space is a crucial component of the interface, allowing users to navigate to specific web pages and access information online.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>17", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "A user working on a computer that is running on Windows 7 issued the command: Ctrl +Alt +Del while typing a document. What interface is expected to be displayed on the screen?", "images": [], "options": {"A": "Restart windows", "B": "Shutdown windows", "C": "Windows hibernate", "D": "Windows task manager"}, "answer": "D", "explanation": "The Ctrl + Alt + Del command in Windows 7 opens the Windows Security screen, which includes options such as Lock this Computer, Switch User, Log Off, Change a Password, and Start Task Manager. Therefore, the correct answer is 'Windows task manager'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>18", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The following computer files will open on a computer that has only Microsoft office 1997 - 2003 installed except", "images": [], "options": {"A": "exam.doc", "B": "exam.docx", "C": "exam.ppt", "D": "exam.rft."}, "answer": "B", "explanation": "Microsoft Office 1997 - 2003 does not support the .docx file format. The .docx format was introduced in Microsoft Office 2007. Therefore, a .docx file ('exam.docx') will not open on a computer that has only Microsoft Office 1997 - 2003 installed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>19", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The part labelled I in Figure 2 is used in Microsoft Word to", "images": ["Data Processing/imgs/2022/dataprocessingq19.jpg"], "options": {"A": "Close current document", "B": "Enlarge current document", "C": "Minimize current document", "D": "Highlight current document"}, "answer": "C", "explanation": "The part labeled 'I' in Figure 2 represents the Minimize button, a common feature found in many applications, including Microsoft Word. Clicking on this button minimizes the current document window, reducing it to a small icon on the taskbar, allowing the user to work on other applications while keeping the document accessible.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>20", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Table 1 is a portion of a Microsoft Excel Worksheet which shows the marks obtained by some students in an examination.   A B C D E F1NAME OF STUDENT ENGLISH LANG MATHEMATICS DATA PROCESSING COMP. STUDIES CIVIC EDUCATION2 ANENE LORRETA 65 90 70 85 653 BAKARE IMAM 60 65 75 80 754 ENEH GRACE 75 65 65 75 605 MOHAMMED DEJI 65 60 65 60 606 ONYEBUEKE DEBORAH 89 65 60 65 65    Which of the following formulas can be used to find the average score for ENEH GRACE?", "images": [], "options": {"A": "=AVERAGE(B4:B6)", "B": "=AVERAGE(B5:F5)", "C": "=AVERAGE(B4:F4)", "D": "=AVERAGE(A4:F4)"}, "answer": "C", "explanation": "The formula \"=AVERAGE(B4:F4)\" is used to calculate the average score for Eneh Grace in Table 1. This formula instructs the spreadsheet software to add together the values contained within cells B4 through F4 and then divide the sum by the number of cells included in the range, providing the average score for Eneh Grace.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>21", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The following statements are steps used in creating a new workbook in a Microsoft Excel application.  I. Click on New  II. Click on the Microsoft Office button  III. Choose blank document    Which of the following arrangements shows the correct order of operation from the steps above?", "images": [], "options": {"A": "I, II and III", "B": "II, I and III", "C": "II, III and I", "D": "III, II and I"}, "answer": "B", "explanation": "The steps used in creating a new workbook in a Microsoft Excel application  - Click on the Microsoft Office button  - Click on New  - Choose blank document", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>22", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The database tool that allows the user to select and filter data from multiple tables is referred to as", "images": [], "options": {"A": "Form", "B": "Query", "C": "Report", "D": "Table"}, "answer": "B", "explanation": "A query in a database is a request for information from a database management system (DBMS), which is the software program that maintains data. Users can make a query to retrieve data or change information in a database, such as adding or removing data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>23", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Arrange the following steps in the correct order for editing data type in data sheet view of a Microsoft Access database  I.\tClick the type of data that that will be entered into the fields  II.\tClick the data sheet tab on the ribbon  III.\tClick the field you wish to define  IV.\tClick the 'down' arrow next to the data type", "images": [], "options": {"A": "I, III, IV and II", "B": "IV, III, II and I", "C": "II, III, I and IV", "D": "III, II, IV and I"}, "answer": "D", "explanation": "- Click the field you wish to define  - Click the data sheet tab on the ribbon  - Click the 'down' arrow next to the data type  - Click the type of data that that will be entered into the fields", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>24", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "In Microsoft PowerPoint, the command: ctrl + m is used to create", "images": [], "options": {"A": "An animation", "B": "New PowerPoint document", "C": "New slide", "D": "New presentation"}, "answer": "C", "explanation": "In Microsoft PowerPoint, the command: ctrl + m is used to create a new slide. This is a shortcut command that allows users to quickly add a new slide to their presentation without having to navigate through the menu options.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>25", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "One example of web design package is", "images": [], "options": {"A": "MS frontpage", "B": "MS outlook", "C": "Peachtree", "D": "SPSS"}, "answer": "A", "explanation": "Other examples of web design package  - Adobe Dreamweaver.  - Google web designers.  - Microsoft SharePoint designer.  - Net Objects fusion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>26", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The part labelled III in Figure 3 is used to", "images": ["Data Processing/imgs/2022/dataprocessingfig3.jpg"], "options": {"A": "Shape objects", "B": "Select and transform objects", "C": "Search for objects", "D": "Change the viewing windows"}, "answer": "C", "explanation": "The part labeled 'III' in Figure 3 represents the search icon, a commonly used feature in CorelDRAW. The search icon allows users to quickly and efficiently locate specific elements, objects, or tools within the software interface by entering relevant keywords or search terms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>27", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Corrective maintenance of software refers to", "images": [], "options": {"A": "Modifications initiated due to defects in software.", "B": "Making the software easier to understand", "C": "Enhancement aimed at making the product faster", "D": "Deploying the software to a different hardware platform"}, "answer": "A", "explanation": "Corrective maintenance is concerned with fixing errors that are observed when the software is in use", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>28", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A desktop computer is switched on and the monitor displays an error message which reads: No input signal. The likely cause of this error is", "images": [], "options": {"A": "Defective monitor", "B": "Disconnected VGA", "C": "Low memory", "D": "Power failure"}, "answer": "B", "explanation": "The error message 'No input signal' on a monitor typically indicates that the monitor is not receiving a signal from the computer. This is most likely due to a disconnected VGA (Video Graphics Array) cable, which is responsible for transmitting video signals from the computer to the monitor. Therefore, the correct answer is 'Disconnected VGA'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>29", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "The legal right given to the owner of an intellectual property to prevent others from duplicating or using the work freely is known as", "images": [], "options": {"A": "Trademark", "B": "Ownership right", "C": "Legal right", "D": "Copyright"}, "answer": "D", "explanation": "A copyright is a type of intellectual property that gives its owner the exclusive right to copy, distribute, adapt, display, and perform a creative work, usually for a limited time. The creative work may be in a literary, artistic, educational, or musical form.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>30", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Which of the following practices is a safety measure?", "images": [], "options": {"A": "Wearing hand gloves while typing", "B": "Opening up the computer while still connected to the power supply", "C": "Maintaining a dust-free environment", "D": "Eating and typing at the same time"}, "answer": "C", "explanation": "Maintaining a dust-free environment is a safety measure. Dust can cause damage to computer components by blocking ventilation ports, causing overheating, and leading to static electricity build-up. Therefore, keeping the computer environment clean and dust-free is a crucial safety measure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>31", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Preventive maintenance measures in computer room do not include", "images": [], "options": {"A": "Good ventilation", "B": "Proper illumination", "C": "The use of rugs", "D": "The use of tiles"}, "answer": "C", "explanation": "Preventive maintenance measures in a computer room are meant to ensure the longevity and optimal performance of the computer systems. This includes good ventilation to prevent overheating, proper illumination for visibility, and the use of tiles for easy cleaning and maintenance. The use of rugs is not a preventive maintenance measure as rugs can accumulate dust and static electricity which can harm computer systems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>32", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "One quality of a computer programmer", "images": [], "options": {"A": "Ability to teach", "B": "Excellent analytical thinking", "C": "Friendliness", "D": "Punctuality to work"}, "answer": "B", "explanation": "Qualities of a computer programmer  - has passion for computers  - has desire for efficiency  - love to learn new technologies  - is a problem solver  - has excellent analytical thinking", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>33", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Which of the following malware does not replicate itself?", "images": [], "options": {"A": "Boot sector virus", "B": "Memory resident virus", "C": "Trojan horse", "D": "Worm"}, "answer": "C", "explanation": "A Trojan Horse Virus is a type of malware that downloads onto a computer disguised as a legitimate program, and does not replicate itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>34", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Computer virus replicates itself into", "images": [], "options": {"A": "Dormant phase", "B": "Execution phase", "C": "Propagation phase", "D": "Trigger phase"}, "answer": "C", "explanation": "In the propagation phase, the virus is fruitful and multiplies. The virus will start to insert copies of itself into other programs or areas on the disk. These copies are often altered in some way to make detection more difficult.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>35", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Table1  P_ ID P_Name Price (₦)1 Cocoa 150   2 Banana 1003 Cowpea 504 Yam 60    Table 2  P_ID    P_Name  Price (₦)     Quantity (kg)1 Cocoa 150 152 Banana 100 173 Cowpea 50 204 Yam 60 10    A suitable application software for creating  Tables 1 and 2  is", "images": [], "options": {"A": "CorelDraw", "B": "MS Access", "C": "MS Powerpoint", "D": "Notepad"}, "answer": "B", "explanation": "MS Access is a suitable application software for creating Tables 1 and 2. It is a database management system from Microsoft that combines the relational Microsoft Jet Database Engine with a graphical user interface and software-development tools. It allows users to create tables, queries, forms and reports, and connect with a variety of data sources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>36", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Table1  P_ ID P_Name Price (₦)1 Cocoa 150   2 Banana 1003 Cowpea 504 Yam 60    Table 2  P_ID    P_Name  Price (₦)     Quantity (kg)1 Cocoa 150 152 Banana 100 173 Cowpea 50 204 Yam 60 10  Table 2 can be derived from table 1 by", "images": [], "options": {"A": "Fragmentation", "B": "Replication", "C": "Redundancy", "D": "Segmentation"}, "answer": "C", "explanation": "Data redundancy is a data organization issue that allows the unnecessary duplication of data within your Microsoft Access database. A change or modification, to redundant data, requires that you make changes to multiple fields of a database.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2022>37", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "When choosing a file organization method a system administrator will not  consider", "images": [], "options": {"A": "File access method", "B": "File activity", "C": "File medium", "D": "Frequency of update"}, "answer": "C", "explanation": "When choosing a file organization method, a system administrator will consider the file access method, file activity, and frequency of update. These factors are important in determining how the files will be organized for efficient access and update. However, the file medium, which refers to the physical material on which data is stored, is not a primary consideration in file organization. Therefore, the correct answer is 'File medium'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>38", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "A file organization method that has reference which identifies a record in relation to other records is called", "images": [], "options": {"A": "Indexed file organization", "B": "Random file organization", "C": "Serial file organization", "D": "Sequential file organization"}, "answer": "A", "explanation": "An indexed file organization contains reference numbers, like employee numbers, that identify a record in relation to other records. These references are called the primary keys that are unique to a particular record.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2022>39", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Frequent backup of computer files helps to", "images": [], "options": {"A": "Archive files", "B": "Modify records in files", "C": "Prevent virus attacks", "D": "Protect files"}, "answer": "D", "explanation": "Frequent backup of computer files helps to protect files. Backups are copies of data that are used to restore the original after a data loss event. They are essential for protecting data from loss due to hardware failures, user errors, or other unforeseen events. Therefore, the correct answer is 'Protect files'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2022>40", "subject": "Data Processing", "year": "2022", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Shared-memory is an architecture in", "images": [], "options": {"A": "Distributed database", "B": "Parallel database", "C": "Relational database", "D": "Trusted distributed database"}, "answer": "B", "explanation": "Shared-memory is the architectural model adopted by recent servers based on symmetric multiprocessors (SMP). It has been used by several parallel database system prototypes and products as it makes DBMS porting easy, using both inter-query and intra-query parallelism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>1", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Artificial intelligence is a feature of", "images": [], "options": {"A": "second generation computers.", "B": "third generation computers.", "C": "fourth generation computers.", "D": "fifth generation computers."}, "answer": "D", "explanation": "Artificial intelligence (AI) is a feature of fifth generation computers.    The first generation of computers were mainframe computers that used vacuum tubes. The second generation of computers used transistors, which were smaller and more efficient than vacuum tubes. The third generation of computers used integrated circuits (ICs), which allowed for even more compact and powerful computers. The fourth generation of computers used microprocessors, which are even smaller and more powerful than ICs.    Fifth generation computers are still in development, but they are expected to use artificial intelligence (AI) to perform tasks that are currently beyond the capabilities of human computers. For example, fifth generation computers could be used to translate languages, diagnose diseases, and write creative content.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>2", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The Difference Engine and the Analytical Engine were invented by", "images": [], "options": {"A": "Ada Lovelace and Charles Babbage.", "B": "Blaise Pascal.", "C": "Charles Babbage.", "D": "Blaise Pascal and Ada Lovelace."}, "answer": "C", "explanation": "The Difference Engine and the Analytical Engine were invented by Charles Babbage.    Blaise Pascal invented the first mechanical calculator, the Pascaline, in the 17th century. However, the Difference Engine and the Analytical Engine were much more sophisticated machines that could perform a wider range of calculations.    Babbage began work on the Difference Engine in the early 1820s. It was a mechanical calculator that could be used to tabulate polynomial functions. The Difference Engine was never completed, but Babbage did build a small prototype.    In the 1830s, Babbage began work on the Analytical Engine. The Analytical Engine was a much more ambitious project than the Difference Engine. It was a general-purpose computer that could be programmed to perform any calculation. The Analytical Engine was never built, but Babbage's design is considered to be the first blueprint for a modern computer.    Ada Lovelace, the daughter of poet Lord Byron, was a collaborator of Babbage's. She is credited with writing the first computer program, which was for the Analytical Engine.    The Difference Engine and the Analytical Engine were revolutionary machines that laid the foundation for the development of modern computers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>3", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following data elements ranks highest in size?", "images": [], "options": {"A": "Bit", "B": "Byte", "C": "Field", "D": "Record"}, "answer": "D", "explanation": "The hierarchy of data size is as follows:    Bit  Byte  Field  Record    A bit is the smallest unit of data and can represent a binary value of 0 or 1. A byte consists of 8 bits. A field is a collection of related data elements, and a record is a collection of fields. So, in terms of size, a byte is larger than a bit, and a field and a record are composed of multiple bytes and potentially multiple fields, respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>4", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The aim of administering questionaire is to collect", "images": [], "options": {"A": "data.", "B": "information.", "C": "statistics.", "D": "specimen."}, "answer": "A", "explanation": "The aim of administering a questionnaire is to collect data.    A questionnaire is a survey that is used to collect information from a group of people. The data collected from a questionnaire can be used for a variety of purposes, such as:    Research: Questionnaires are often used by researchers to collect data for their studies. For example, a researcher might use a questionnaire to collect data about people's attitudes towards a certain issue.  Marketing: Questionnaires can also be used by businesses to collect data about their customers. For example, a business might use a questionnaire to collect data about customer satisfaction with their products or services.  Evaluation: Questionnaires can also be used to evaluate the effectiveness of a program or intervention. For example, a school might use a questionnaire to collect data about the effectiveness of a new curriculum.  The data collected from a questionnaire can be used to answer questions, make decisions, and improve programs and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>5", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which of the following computer types represents data as variable and continuous values?", "images": [], "options": {"A": "Analogue computer", "B": "Digital computer", "C": "Mainframe computer", "D": "Microcomputer"}, "answer": "A", "explanation": "Analogue computer represents data as variable and continuous values.    Analogue computers use physical quantities, such as voltage, current, or resistance, to represent data. This means that they can represent data that is continuously varying, such as the position of a moving object or the temperature of a substance.    Digital computers, on the other hand, represent data as discrete values. This means that they can only represent data that is in a finite number of states, such as the numbers 0 and 1.    Mainframe computers and microcomputers are both digital computers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>6", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "A digital platform for the delivery of public sector information and seminar to citizens is called", "images": [], "options": {"A": "e-library.", "B": "e-government.", "C": "e-commerce.", "D": "e-learning."}, "answer": "B", "explanation": "A digital platform for the delivery of public sector information and seminars to citizens is called e-government. E-government refers to the use of digital technology to provide government services, information, and communication to the public. It encompasses various online services, information dissemination, and interactions between the government and citizens through digital means. E-library, e-commerce, and e-learning are related terms but refer to different concepts: online libraries, online commerce, and online learning, respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>7", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "One application of  ICT  in medicine is", "images": [], "options": {"A": "global positioning system.", "B": "seismic software.", "C": "computerized axial tomography.", "D": "optical character recognition."}, "answer": "C", "explanation": "One application of ICT (Information and Communication Technology) in medicine is computerized axial tomography (CAT or CT scan). Computerized axial tomography is a medical imaging technique that uses X-rays and computer processing to create detailed cross-sectional images of the body's internal structures. It is used for diagnosing and monitoring various medical conditions by providing detailed images of organs, tissues, and bones.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>8", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A pointing device that controls cursor movement on the screen is", "images": [], "options": {"A": "keyboard.", "B": "monitor.", "C": "plotter.", "D": "trackball."}, "answer": "D", "explanation": "A pointing device that controls cursor movement on the screen is a trackball.    A trackball is a small, ball-shaped device that is used to control the movement of the cursor on a computer screen. The trackball is held in place by a socket and is rotated by the user's fingers. The rotation of the trackball causes the cursor to move in the corresponding direction on the screen.    Trackballs are often used in laptops and other portable devices where there is limited space for a mouse. They are also used by people with disabilities who have difficulty using a mouse.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>9", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The process of drawing inference from a piece of information is called", "images": [], "options": {"A": "analysis.", "B": "collation.", "C": "interpretation.", "D": "organization."}, "answer": "C", "explanation": "The process of drawing inference from a piece of information is called interpretation.    Analysis is the process of breaking down a whole into its parts and examining those parts. Collation is the process of bringing together information from different sources. Organization is the process of arranging information in a logical order.    Interpretation is the process of making meaning from information. It involves using our knowledge and experience to make sense of what we see, hear, and read. When we interpret information, we are drawing inferences about what it means. We are making connections between the information and our own knowledge and experience.    For example, if we read a news article about a car accident, we might interpret the information to mean that the driver was speeding. We might make this inference because we know that speeding is a common cause of car accidents. We might also make this inference because the article mentions that the driver was not wearing a seatbelt. We know that not wearing a seatbelt is also a common cause of car accidents.    Interpretation is an important skill for critical thinking. It allows us to make sense of the world around us and to make informed decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>10", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The information processing stage that produces detailed evaluation of data is", "images": [], "options": {"A": "analysis.", "B": "collection.", "C": "interpretation.", "D": "organization."}, "answer": "A", "explanation": "The information processing stage that produces detailed evaluation of data is analysis.    Analysis is the process of breaking down information into its component parts and examining those parts. It is a detailed evaluation of data to identify patterns, trends, and relationships. Analysis can be used to answer questions, make decisions, and solve problems.    In the context of information processing, analysis is the stage where the data is examined in detail to identify its meaning. This may involve identifying patterns, trends, and relationships in the data. It may also involve comparing the data to other data sets or to known standards.    The analysis stage is an important part of the information processing cycle. It is the stage where the data is transformed from raw data into information that can be used to make decisions and solve problems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>11", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The volume of data that can be sent from one point to another in a given time period is called", "images": [], "options": {"A": "baud.", "B": "bandwidth.", "C": "byte.", "D": "broadband."}, "answer": "B", "explanation": "The volume of data that can be sent from one point to another in a given time period is called bandwidth. Bandwidth refers to the capacity of a communication channel to transmit data, typically measured in bits per second (bps) or its multiples like kilobits per second (Kbps), megabits per second (Mbps), and so on. It represents how much data can be transmitted over a network connection within a specific time frame.    Baud is a unit of data signaling rate, or the number of times per second that a signal changes state.  Byte is a unit of digital information, equal to 8 bits.  Broadband is a high-speed data transmission medium that can carry multiple signals simultaneously.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>12", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The equipment shown in Figure 1 is used for", "images": ["Data Processing/imgs/2023/2023_dpr_one_two.jpg"], "options": {"A": "audio transmission.", "B": "ethernet connection.", "C": "infrared transmission.", "D": "radio transmission."}, "answer": "D", "explanation": "Radio transmission refers to the process of sending and receiving information using radio waves, which are a type of electromagnetic radiation. Radio waves are used for various forms of communication, including broadcasting, wireless communication, and remote control systems", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>13", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Use the information below to answer questions 13 and 14.   A student in the school hostel was able to upload some personal details on the school portal via the school's  WiFi .  The  ISP  and the hostel are both domiciled in the school premises.    What type of network is illustrated above?", "images": [], "options": {"A": "LAN", "B": "MAN", "C": "PAN", "D": "WAN"}, "answer": "A", "explanation": "The type of network illustrated above is a LAN or Local Area Network.    A LAN is a network that connects devices in a limited area, such as a school, office, or home. LANs are typically used to connect computers, printers, and other devices together.    In the given scenario, the student is using the school's WiFi to upload personal details on the school portal. The WiFi is a wireless LAN that connects the student's device to the school's network. The ISP and the hostel are both domiciled in the school premises, which means that they are all part of the same LAN.    MAN or Metropolitan Area Network is a network that covers a larger area than a LAN, such as a city or a campus. WAN or Wide Area Network is a network that covers a large geographic area, such as a country or the world. PAN or Personal Area Network is a network that connects devices close to a person, such as a laptop, smartphone, and printer.    In this case, the network is limited to the school premises, so it is a LAN.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>14", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "Use the information below to answer questions 13 and 14.   A student in the school hostel was able to upload some personal details on the school portal via the school's  WiFi .  The  ISP  and the hostel are both domiciled in the school premises.  The physical infrastructure through which internet traffic are exchanged between the  ISP  in the school illustrated above and other  ISP s is called", "images": [], "options": {"A": "internet exchange point.", "B": "server farms.", "C": "subscriber end points.", "D": "switch racks."}, "answer": "A", "explanation": "The physical infrastructure through which internet traffic are exchanged between the ISP in the school illustrated above and other ISP s is called an internet exchange point or IXP.    An IXP is a facility where multiple networks can connect to each other and exchange traffic. This allows ISPs to exchange traffic directly with each other, without having to go through a third party. This can improve performance and reduce costs.    In the given scenario, the ISP in the school will connect to an IXP to exchange traffic with other ISPs. This will allow the student to upload personal details on the school portal, even if the student's ISP is different from the ISP that hosts the school portal.    Server farms, subscriber end points, and switch racks are all part of the physical infrastructure of the internet, but they are not used to exchange traffic between ISPs.    Server farms are facilities that house large numbers of servers. These servers are used to host websites, applications, and other services.    Subscriber end points are the devices that connect users to the internet. This can include computers, smartphones, and tablets.    Switch racks are cabinets that house switches. Switches are devices that connect devices on a network together.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>15", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Figure 2 is an email application interface.  Use it to answer questions 15 and 16.         New messages received are save in the part labelled", "images": ["Data Processing/imgs/2023/B7ANFK.jpg"], "options": {"A": "I.", "B": "II.", "C": "III.", "D": "IV."}, "answer": "B", "explanation": "New messages that are received are typically saved in the inbox of an email application interface. The inbox is where incoming emails are displayed, allowing the user to see and manage new messages that have been received. The other options provided—New, sent items, and drafts—refer to different folders or sections within an email application, each serving a specific purpose:    New: This might refer to a \"New Message\" button or option, allowing you to compose and send new emails.  Sent Items: This folder contains copies of emails you have sent.  Drafts: This folder holds emails that you have started composing but have not yet sent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>16", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Figure 2 is an email application interface.  Use it to answer questions 15 and 16.       To send an e-mail, the user must click on the part labelled", "images": ["Data Processing/imgs/2023/B7ANFK.jpg"], "options": {"A": "I.", "B": "II.", "C": "III.", "D": "IV."}, "answer": "A", "explanation": "To send an e-mail, the user typically clicks on the \"New\" part of the email application interface. This option allows the user to compose a new email message and enter the recipient's email address, subject, and content before sending it. The \"New\" button or option is used to initiate the process of creating a new email to be sent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>17", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "The allocation and de-allocation of computing resources in a computer is the function of", "images": [], "options": {"A": "application software.", "B": "browsers.", "C": "memory unit.", "D": "operating system."}, "answer": "D", "explanation": "The allocation and de-allocation of computing resources in a computer is the function of the operating system. The operating system is responsible for managing various hardware and software resources, including memory, processing power, storage, and input/output devices. It ensures that different applications and processes run smoothly by allocating resources as needed and de-allocating them when they are no longer required. Application software, browsers, and memory units may interact with the operating system, but the primary responsibility for resource management lies with the operating system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>18", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Which of the following alignment styles can be achieved when the command Ctrl + J is executed in  Ms Word ?", "images": ["Data Processing/imgs/2023/2023_dpr_one_eight_opt_a.png", "Data Processing/imgs/2023/2023_dpr_one_eight_opt_b.png", "Data Processing/imgs/2023/2023_dpr_one_eight_opt_c.png", "Data Processing/imgs/2023/2023_dpr_one_eight_opt_d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "In Microsoft Word, the keyboard shortcut Ctrl + J is used to justify the selected text or paragraph. Justifying the text means adjusting the spacing between words so that both the left and right edges of the text are aligned, creating a clean and even appearance along both margins. This is often referred to as full justification.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>19", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "The ruler feature in  MS  Word that is used to indent the second and subsequent lines of a paragraph is", "images": [], "options": {"A": "hanging indent.", "B": "left indent.", "C": "left margin.", "D": "right indent."}, "answer": "A", "explanation": "The ruler feature in MS Word that is used to indent the second and subsequent lines of a paragraph is hanging indent. A hanging indent is when the first line of a paragraph starts at the left margin, but the following lines are indented, creating a visually staggered appearance. This is often used in bibliographies, reference lists, and other situations where the first line needs to be flush with the left margin, while subsequent lines are indented.    To create a hanging indent in MS Word, you can follow these steps:    Click on the Paragraph tab.  In the Indentation section, click on the Special drop-down menu and select Hanging.  Enter the amount of indent that you want for the second and subsequent lines in the By box.  Click on the OK button.  The second and subsequent lines of the paragraph will now be indented.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>20", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Figure 3 is a Microsoft Excel Worksheet.  Use it to answer questions 20 and 21.     ABCDE1IDENTICATION NUMBERBASIC SALARY (N)TOTAL ALLOWANCE (N)TOTAL DEDUCTION (N)NET SALARY (N)2WASC/LPT/00180000060000400008200003WASC/LPT/00270000040000200007200004WASC/LPT/0033000001000050003050005WASC/LPT/0044000002000010000410000Figure 3    What formula will correctly display the total number of individuals involved in the computation as shown in Figure 3?", "images": [], "options": {"A": "=COUNT(A2:A5)", "B": "=COUNTA(A2:A5)", "C": "=COUNTIF(A2:A5)", "D": "=SUM(A2:A5)"}, "answer": "B", "explanation": "The formula that will correctly display the total number of individuals involved in the computation as shown in Figure 3 is COUNTA(A2:A5).    The COUNTA function counts the number of cells that are not empty in a range. In this case, we want to count the number of cells in the A column that are not empty. The A column contains the identification numbers of the individuals involved in the computation. Therefore, the COUNTA function will return the total number of individuals involved in the computation.    The other formulas mentioned are:    COUNT: This function counts the number of cells that contain numbers in a range.  COUNTIF: This function counts the number of cells that contain a specific value in a range.  SUM: This function sums the values in a range.    In this case, we do not want to count the number of cells that contain numbers or the number of cells that contain a specific value. We want to count the number of cells that are not empty. Therefore, the COUNTA function is the most appropriate function to use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>21", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "Figure 3 is a Microsoft Excel Worksheet.  Use it to answer questions 20 and 21.     ABCDE1IDENTICATION NUMBERBASIC SALARY (N)TOTAL ALLOWANCE (N)TOTAL DEDUCTION (N)NET SALARY (N)2WASC/LPT/00180000060000400008200003WASC/LPT/00270000040000200007200004WASC/LPT/0033000001000050003050005WASC/LPT/0044000002000010000410000Figure 3  What formula will calculate the total number of individuals who earn less than ₦500,000 from the table as shown in Figure 3?", "images": [], "options": {"A": "=COUNTA(E2:E5)", "B": "=COUNT(E2:E5)", "C": "=COUNT(E2:E5,\"", "D": "=COUNTIF(E2:E5,\""}, "answer": "D", "explanation": "The formula that will calculate the total number of individuals who earn less than ₦500,000 from the table as shown in Figure 3 is COUNTIF(E2:E5, \"   The COUNTIF function counts the number of cells that contain a specific value in a range. In this case, we want to count the number of cells in the E column that contain a value less than ₦500,000. The E column contains the net salaries of the individuals. Therefore, the COUNTIF function will return the total number of individuals who earn less than ₦500,000.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>22", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Figure 4 is an entity relationship diagram in MS Access.  Use it to answer questions 22 and 23.       How many entity are listed in Figure 4?", "images": ["Data Processing/imgs/2023/2023_dpr_two_two.png"], "options": {"A": "3", "B": "5", "C": "25", "D": "30"}, "answer": "B", "explanation": "In an Entity-Relationship (ER) diagram, an entity represents a distinct and identifiable concept, object, or thing about which data is being stored. Entities are typically nouns that have attributes describing their properties. They serve as the building blocks of an ER diagram and are used to model the real-world entities or concepts that are relevant to the database being designed.    For example, in a university database, entities could include \"Student,\" \"Course,\" \"Professor,\" and \"Department,\" each with their own set of attributes that describe their characteristics. Relationships between entities, indicated by lines connecting them, show how these entities are related to one another and how data flows between them.    But in the Entity-Relationship (ER) diagram given above, the entities are \"Users\", \"Products\", \"Sale\", \"Sale detail\", and \"Sale detail TMP\" which are five (5) in numbers", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>23", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Figure 4 is an entity relationship diagram in MS Access.  Use it to answer questions 22 and 23.     What kind of relationship exists between users and products as shown in Figure 4?", "images": ["Data Processing/imgs/2023/2023_dpr_two_two.png"], "options": {"A": "One-to-many", "B": "One-to-one", "C": "Many-to-many", "D": "Many-to-one"}, "answer": "A", "explanation": "Looking at the arrow (relation) that connects Products table to the Users table. The infinity sign beside the products table represents the \"Many\" part of the relationship which is not present at the Users table (i.e it is \"One\" part of the relationship) . This means that a user can buy \"any\" number of products but a product can only be bought by \"a\" user. Therefore, the relationship between the \"users\" and \"products\" is one-to-many.    NB: Users are assumed to be buying products for illustration purposes.    Many-to-one relationship is if it's between the \"Products\" and the \"Users\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>24", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "Figure 5 is an  MS PowerPoint  application interface. The part used to apply motion effect to different objects of a slide is labelled", "images": ["Data Processing/imgs/2023/2023_dpr_two_four.jpg"], "options": {"A": "I.", "B": "II.", "C": "III.", "D": "IV."}, "answer": "B", "explanation": "The part used to apply motion effects to different objects of a slide in PowerPoint is \"Animation\". Animation effects in MS PowerPoint allow users to add movement, entrance, exit, and emphasis to individual objects on a slide. These effects help make presentation more dynamic and engaging.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>25", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Macromedia Dreamweaver application is used for", "images": [], "options": {"A": "graphic design.", "B": "intranet communication.", "C": "surfing the internet.", "D": "web design."}, "answer": "D", "explanation": "Macromedia Dreamweaver (now part of Adobe Creative Cloud) is an application primarily used for web design. It's a professional web development tool that allows designers and developers to create, edit, and manage websites and web applications. Dreamweaver provides a visual interface for designing web pages and also offers coding capabilities for those who want to work with HTML, CSS, JavaScript, and other web technologies.    The application is not used for graphic design, intranet communication, or general internet browsing, as its main focus is on web development and design.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>26", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The following feature are found in the toolbox of CorelDraw application except", "images": [], "options": {"A": "elipse tool.", "B": "marque tool.", "C": "rectangle tool.", "D": "text tool."}, "answer": "B", "explanation": "The feature that is not found in the toolbox of CorelDraw application is the marque tool. While CorelDraw does offer tools for creating and manipulating shapes like ellipses, rectangles, and text, it does not typically include a specific \"marque tool.\"", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>27", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "When performing computer recovery operations after a system crash, the startup disk is used to", "images": [], "options": {"A": "backup deleted users file.", "B": "recover the system disk from an image file.", "C": "restore the system to an earlier time.", "D": "update the application packages."}, "answer": "B", "explanation": "When performing computer recovery operations after a system crash, the startup disk is used to recover the system disk from an image file.    A startup disk typically contains essential system files and tools that are required to boot the computer and initiate recovery procedures. One common approach to recovery after a system crash is to use an image of the system disk taken at a stable and functional state. This image is often referred to as a \"system image\" or \"backup image.\" By using the startup disk and this image, you can restore the entire system to a previous state, which can include the operating system, applications, and data. This process helps in recovering from crashes and issues that render the system inoperable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>28", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "A computer system under use was found to be unusually slow, freezes often and very dusty. What is needed to correct this problem?", "images": [], "options": {"A": "Change the location of the computer", "B": "Delete some files", "C": "Hit the system unit with a blower.", "D": "Perform maintenance procedure"}, "answer": "D", "explanation": "To correct the described problems of a slow, freezing computer system that is also very dusty, the appropriate action is to perform maintenance procedures.    Performing maintenance procedures could involve the following steps:    Cleaning: Dust accumulation can lead to overheating and hinder proper airflow, causing the system to slow down or freeze. Open the computer's case and carefully clean the components using compressed air or an electronics-friendly blower.    Checking for Malware: Slow performance and freezing can be caused by malware infections. Run a thorough malware scan to ensure the system is not compromised.    Checking for Software Issues: Excessive background processes or malfunctioning software can also slow down a computer. Review and uninstall unnecessary or problematic applications.    Updating Software: Ensure that the operating system, drivers, and applications are up to date. Sometimes, updates can address performance issues.    Checking Hardware: Inspect hardware components for any visible damage or loose connections. Reseat RAM, check the hard drive's health, and make sure all components are properly seated.    Removing Unnecessary Files: While deleting unnecessary files might help free up storage space, it might not directly address the issues mentioned.    Note: Hitting the system unit with a blower is not recommended as it could potentially cause further damage to the hardware components. It's important to handle the hardware gently and follow appropriate cleaning methods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>29", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Computer ethical practises include the following except", "images": [], "options": {"A": "exposure of vulnerability in websites.", "B": "respect for intellectual property.", "C": "use of polite words on other users.", "D": "use of other people&#8217;s computer without due permission."}, "answer": "D", "explanation": "Computer ethical practices include the following, but they do not include:    Use of other people's computer without due permission.    The other options listed are generally considered ethical practices in the realm of computer use and technology. However, using someone else's computer without permission is a violation of privacy and unauthorized access, which goes against ethical guidelines. It's important to respect the rights and ownership of others' devices and data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>30", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Which of the following devices is needed by a technician for protection against electrostatic discharge?", "images": [], "options": {"A": "Magnet", "B": "Screw driver", "C": "Surge protector", "D": "Wrist strap"}, "answer": "D", "explanation": "A wrist strap is needed by a technician for protection against electrostatic discharge (ESD).    ESD is a sudden discharge of electricity that can damage electronic components. It can occur when two objects with different electrical charges come into contact. When working on electronic components, it is important to prevent ESD from damaging them.    A wrist strap is a device that helps to prevent ESD by dissipating the electrical charge from the body to the ground. It is worn around the wrist and connected to a grounding point, such as a metal pipe or a ground rod.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>31", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "People who use cathode ray tube monitor without antiglare screen are susceptible to", "images": [], "options": {"A": "back ache.", "B": "repetitive strain injury.", "C": "blurred vision.", "D": "stiffness of the wrist."}, "answer": "C", "explanation": "People who use cathode ray tube (CRT) monitors without antiglare screens are susceptible to blurred vision. CRT monitors emit a significant amount of glare and can cause reflections on the screen due to ambient light sources. This glare and reflection can lead to visual discomfort, including blurred vision and eyestrain, when using the monitor for extended periods.    Antiglare screens or filters are used to reduce glare and reflections, making the screen easier to view and reducing the strain on the eyes. While CRT monitors are less common today, the issue of glare and visual discomfort is relevant to any type of screen, including modern LCD and LED displays.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>32", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Database Administrator is a professional who", "images": [], "options": {"A": "tests and detects vulnerabilities on hardware devices and software.", "B": "handles packet sniffing in a network.", "C": "designs, implements and maintains a database.", "D": "performs data entry in a database."}, "answer": "C", "explanation": "A Database Administrator is a professional who designs, implements, and maintains a database. Database administrators are responsible for managing and overseeing the organization's databases to ensure they are efficient, secure, and reliable. Their tasks include designing the database structure, implementing data models, optimizing database performance, ensuring data security, creating backup and recovery plans, and more. They play a crucial role in ensuring that data is organized, accessible, and properly managed within an organization's database systems.    The other options mentioned—testing and detecting vulnerabilities, handling packet sniffing, and performing data entry—are tasks related to network security, network analysis, and data input, respectively, but they are not the primary responsibilities of a Database Administrator.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>33", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "The following precautionary measures are taken against virus infection except", "images": [], "options": {"A": "regular updating of antivirus.", "B": "downloading e-mail and attachment before scanning it.", "C": "avoiding the installation of piratted software.", "D": "avoiding booting the computer with disks in it."}, "answer": "B", "explanation": "The precautionary measure downloading e-mail and attachment before scanning it is not taken against virus infection.    Here are some precautionary measures that can be taken against virus infection:    Regularly updating your antivirus software: This ensures that your antivirus software has the latest virus definitions to protect your computer from new viruses.  Avoiding opening suspicious e-mails and attachments: Many viruses are spread through e-mails and attachments. If you receive an e-mail from someone you don't know, or if the e-mail looks suspicious, don't open it.  Avoiding installing pirated software: Pirated software often contains viruses. If you don't want to get a virus, only install software from trusted sources.  Avoiding booting your computer with disks in it: If you boot your computer with a disk in it, the virus on the disk could infect your computer. Only boot your computer with disks from trusted sources.  It is important to note that no single precautionary measure can guarantee that your computer will not be infected with a virus. However, by taking all of these precautions, you can significantly reduce your risk of infection.    The precautionary measure of downloading e-mail and attachment before scanning it is not effective because viruses can be embedded in the e-mail or attachment itself. By downloading the e-mail or attachment, you are essentially giving the virus access to your computer.    It is better to scan the e-mail or attachment first before downloading it. If the scan finds a virus, you can delete the e-mail or attachment without putting your computer at risk.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>34", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Computer malware is detected by", "images": [], "options": {"A": "adware.", "B": "antivirus.", "C": "antiglare.", "D": "logic bomb."}, "answer": "B", "explanation": "Computer malware is detected by antivirus software. Antivirus software is designed to identify, prevent, and remove various types of malicious software, commonly referred to as malware. This includes viruses, worms, trojans, spyware, adware, and other malicious programs that can harm or compromise a computer system. Antivirus software scans files, programs, and incoming data for patterns and behaviors associated with known malware, and it takes actions to quarantine or remove the detected threats. The other options mentioned—adware, antiglare, and logic bomb—are not directly related to detecting malware. Adware is a type of potentially unwanted software, antiglare refers to a screen feature, and a logic bomb is a type of malicious code that triggers when specific conditions are met.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2023>35", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Use Table 1 to answer questions 35 and 36.     Table 1: TableStudent  Reg NoHouseAge18/001Yellow1418/002Blue1518/003Yellow15    Columns 2 and 3 in Table 1 cannot be used as primary key because both fields contain", "images": [], "options": {"A": "the same datatype.", "B": "only strings and numbers respectively.", "C": "duplicate values.", "D": "different datatypes."}, "answer": "C", "explanation": "Columns 2 and 3 in Table 1 cannot be used as a primary key because both fields contain duplicate values.    A primary key is a unique identifier for each record in a database table. It ensures that each record has a distinct value, allowing for efficient data retrieval and maintaining data integrity. In the given TableStudent, the \"House\" column (Column 2) and the \"Age\" column (Column 3) both contain duplicate values. For example, the House column has two records with the value \"Yellow\" and the Age column has two records with the value \"15\". Since a primary key must have unique values, neither of these columns can be used as the primary key.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>36", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "Use Table 1 to answer questions 35 and 36.     Table 1: TableStudent  Reg NoHouseAge18/001Yellow1418/002Blue1518/003Yellow15  The attributes in Table 1 are", "images": [], "options": {"A": "18/001, 18/002, 18/003", "B": "Yellow, Blue, Yellow", "C": "14, 15, 15", "D": "Reg. No, House, Age"}, "answer": "D", "explanation": "The attributes in Table 1 are Reg. No, House, and Age.    An attribute is a single piece of data about an entity. In Table 1, each row represents a student entity. The Reg. No, House, and Age columns represent the attributes of the student entity.    The values in the Reg. No column are unique, so the Reg. No column is the primary key of the table. The House and Age columns are not unique, so they cannot be used as primary keys.    The other values in the table are the data for the attributes. For example, the value \"18/001\" in the Reg. No column is the data for the Reg. No attribute of the first student entity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>37", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The speed of access to files in a random access file compared to other file organization methods is", "images": [], "options": {"A": "relatively fast.", "B": "slow.", "C": "the same.", "D": "very slow."}, "answer": "A", "explanation": "The speed of access to files in a random access file compared to other file organization methods is relatively fast.    Random access files allow direct and immediate access to any part of the file without having to sequentially read through the entire file. This is particularly advantageous when you need to retrieve or modify specific records or data within the file. In contrast, other file organization methods like sequential access require reading through the file from the beginning to reach the desired location, which can be slower for large files.    So, random access files are known for their efficiency in accessing data, especially when compared to methods that involve sequential searching or scanning.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>38", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "A type of file organization that stores data in the order of their arrival is called", "images": [], "options": {"A": "sequential file organization.", "B": "random file organization.", "C": "indexed-sequential file organization", "D": "hashed file organization"}, "answer": "A", "explanation": "A type of file organization that stores data in the order of their arrival is called sequential file organization.    In sequential file organization, records are stored in the order in which they are added to the file. This means that the first record in the file is the oldest record, and the last record in the file is the newest record.    Sequential file organization is a simple and efficient way to store data that is accessed in a sequential order. For example, sequential file organization is often used to store data that is logged in chronological order.    However, sequential file organization can be inefficient for accessing data in a random order. For example, if you want to access the 10th record in a sequential file, you have to read the first 9 records before you can access the 10th record.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2023>39", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "The following terms describe the importance of data security except data", "images": [], "options": {"A": "availability.", "B": "consistency.", "C": "integrity.", "D": "normalization."}, "answer": "D", "explanation": "The term that does not describe the importance of data security is normalization.    Data security focuses on ensuring the confidentiality, integrity, and availability of data. The terms provided—availability, consistency, and integrity—are all related to aspects of data security:    Availability: Ensures that data is accessible and available when needed, without unauthorized disruptions.    Consistency: Ensures that data remains consistent and accurate across different parts of the system.    Integrity: Ensures that data remains accurate and unaltered throughout its lifecycle, preventing unauthorized or unintended modifications.    Normalization, on the other hand, is a database design technique used to structure data in a way that reduces redundancy and ensures efficient data storage and retrieval. While normalization is important for database design, it is not directly related to data security in the same way that availability, consistency, and integrity are.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2023>40", "subject": "Data Processing", "year": "2023", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Advantages of parallel database include the following except", "images": [], "options": {"A": "greater flexibility.", "B": "high availability.", "C": "high performance.", "D": "huge resources."}, "answer": "D", "explanation": "The advantages of parallel database include the following except huge resources.    Advantages of parallel databases typically include:    Greater Flexibility: Parallel databases can distribute and process data across multiple nodes, providing flexibility in handling various types of queries and workloads.    High Availability: Parallel databases can offer improved fault tolerance and availability through redundancy and distribution of data.    High Performance: Parallel processing allows for faster query execution and data processing, especially for complex analytical queries.    However, \"huge resources\" is not typically considered an advantage of parallel databases. While parallel databases can efficiently utilize resources across multiple nodes, the emphasis is on utilizing resources effectively rather than simply having a large quantity of resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>1", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : HISTORY OF COMPUTERS", "question": "The Stepped Reckoner was developed by", "images": [], "options": {"A": "Gottfied Leibinitz", "B": "Herman Hollerith", "C": "John Von Neumann", "D": "William Schickard"}, "answer": "A", "explanation": "The Stepped Reckoner was developed by Gottfried Wilhelm Leibniz, a German mathematician and philosopher, in the late 17th century. It was a mechanical calculator that used a stepped drum, known as the Leibniz wheel, to perform arithmetic operations. Leibniz built two Stepped Reckoners, one in 1694 and one in 1706.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>2", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The binary number 1001012 can be written in denary as", "images": [], "options": {"A": "25", "B": "37", "C": "45", "D": "211"}, "answer": "B", "explanation": "1001012 = 1 × 25 + 0 × 24 + 0 × 23 + 1 × 22 + 0 × 21 + 1 × 20    = (1 × 32) + (0 × 16) + (0 × 8) + (1 × 4) + (0 × 2) + (1 × 1)    = 32 + 0 + 0 + 4 + 0 + 1     = 37", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>3", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The first stage in computer data processing procedure is", "images": [], "options": {"A": "collection of data", "B": "communication of information", "C": "conversion of data", "D": "manipulation of data"}, "answer": "A", "explanation": "The first stage in the computer data processing procedure is indeed the collection of data. This involves gathering raw data from various sources, such as user input, sensors, files, or databases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>4", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "One advantage of electronic data processing is that it", "images": [], "options": {"A": "involves special skill", "B": "deals only with simple data", "C": "is completely error-free", "D": "handles complex data"}, "answer": "D", "explanation": "Electronic data processing (EDP) offers several advantages, including:    - Ability to handle large volumes of complex data quickly and accurately  - Automation of repetitive tasks  - Improved data security and integrity  - Enhanced decision-making capabilities  - Increased productivity and efficiency    EDP enables organizations to process complex data, such as numerical calculations, data analysis, and simulations, with speed and accuracy. This has revolutionized various industries, including finance, healthcare, and science.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>5", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "The type of computer that has the ability of counting in discrete form is referred to as", "images": [], "options": {"A": "analogue computer", "B": "digital computer", "C": "hybrid computer", "D": "versatile computer"}, "answer": "B", "explanation": "A digital computer is a type of computer that processes information in discrete form, using binary digits (bits) to represent data. It can only understand and process discrete values, like 0s and 1s, and is designed to perform calculations and logical operations on this discrete data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>6", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "One reason for using Computer Aided Design in manufacturing is that", "images": [], "options": {"A": "it uses few system resources", "B": "manufacturing time is reduced", "C": "designers do not need training to use it", "D": "3D designs are easily produced with it"}, "answer": "B", "explanation": "One of the primary reasons for using Computer-Aided Design (CAD) in manufacturing is to reduce manufacturing time. CAD software allows designers to create and modify designs digitally, which can significantly speed up the design process. This, in turn, can lead to faster product development and reduced time-to-market. Additionally, CAD can help to identify potential design flaws and manufacturing issues early on, which can further reduce manufacturing time and costs.    \"3D designs are easily produced with it\" is true, but the primary advantage relevant to manufacturing is the reduction in time, making \"manufacturing time is reduced\" the most accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>7", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET~~INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Which one of the following statements is true about Voice Over IP? It", "images": [], "options": {"A": "converts voice and video data into a digital signal and transfers it over the Internet", "B": "converts voice and video data into a digital signal and broadcasts it via a transmitter", "C": "is a voice over communication system which is cyber-attack proof", "D": "is a circuit-switched data communication system"}, "answer": "A", "explanation": "Converts voice and video data signal into a digital signal and transfers it over the Internet.    Voice over Internet Protocol (VoIP) is a technology that converts analog voice and video signals into digital data packets and transmits them over the Internet. This allows for real-time communication, such as voice and video calls, to be made over the Internet.    VoIP offers several benefits, including:    - Cost-effective communication  - Increased mobility and flexibility  - Enhanced features and functionality  - Scalability and adaptability", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>8", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS~~INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Which one of the following sets of devices can be used to store data during processing?", "images": [], "options": {"A": "Cache, RAM and Register", "B": "Cache, Register and ROM", "C": "Flash Drive, ROM and Hard Disk Drive", "D": "RAM, Register and Zip Drive"}, "answer": "A", "explanation": "During processing, data is temporarily stored in:    1. Registers: Small amounts of data are stored in processor registers for quick access and processing.  2. RAM (Random Access Memory): Data is stored in RAM for rapid access and processing. RAM is volatile, meaning data is lost when power is turned off.  3. Cache: A small, fast memory within the processor that stores frequently accessed data to reduce access time.    These three options (Cache, RAM, and Register) are used to store data during processing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>9", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION~~INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "The process of inspecting, transforming and modeling data to get useful information is known as", "images": [], "options": {"A": "collation", "B": "interpretation", "C": "execution", "D": "analysis"}, "answer": "D", "explanation": "Data analysis is the process of inspecting, transforming, and modeling data to extract useful information, patterns, and insights. It involves various techniques, such as:    1. Data cleaning and preprocessing  2. Data visualization  3. Statistical analysis  4. Machine learning  5. Data mining    The goal of data analysis is to turn raw data into actionable information, supporting decision-making, problem-solving, and business intelligence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>10", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "One disadvantage of using computer for information processing is", "images": [], "options": {"A": "need for staff retraining", "B": "increased running cost in the long run", "C": "the increase in storage space", "D": "redundancy of computers in the long run"}, "answer": "A", "explanation": "One of the primary disadvantages of using computers for information processing is the need for staff retraining. When organizations adopt new computer systems or software, employees often require training to learn how to use these systems effectively. This can be time-consuming, costly, and may temporarily reduce productivity as staff adapt to the new technology.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>11", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "The diagram in the Figure 1 illustrates a process called", "images": ["Data Processing/imgs/2024/64K2EP.png"], "options": {"A": "information processing", "B": "information transmission", "C": "modulation", "D": "synchronization"}, "answer": "B", "explanation": "Information transmission is the process of sending data from one point to another. It's the foundation of modern communication, enabling everything from simple phone calls to complex global networks.    Key Components and Processes  Encoding: Converting information into a digital format that can be transmitted.  Transmission Medium: The channel used to send the data. This could be a physical cable (like Ethernet), wireless signals (like Wi-Fi), or even light (like fiber optics).  Modulation: The process of encoding information onto a carrier signal, making it suitable for transmission over a specific medium.  Demodulation: The reverse process of extracting information from the carrier signal at the receiving end.  Decoding: Converting the received digital data back into its original format.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>12", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The transmitter in communication is the component that", "images": [], "options": {"A": "decodes sender's signal by interpretation", "B": "encodes interpreted data by using machine language", "C": "broadcasts synchronous signals", "D": "launches signal into the air"}, "answer": "D", "explanation": "In communication systems, the transmitter is responsible for converting the information (usually in the form of electrical signals) into a form that can be transmitted over a communication medium. This often involves modulating the signal and then launching it into the air as radio waves (in the case of wireless communication) or through a wired medium.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>13", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION", "question": "Which of the following resources is not usually shared in a network?", "images": [], "options": {"A": "VGA projector", "B": "Laserjet printer", "C": "Folder", "D": "File"}, "answer": "A", "explanation": "The correct answer is: VGA projector.    Explanation:    VGA projectors are usually not shared over a network because they are hardware devices used for displaying visual content directly from a computer or other media device. They are connected physically to a single computer and not accessible over a network.    \"Laserjet printer\" is often shared in a network so that multiple users can print documents from different devices.    \"Folder\" is commonly shared over a network to allow multiple users to access, store, or edit files within the folder.    \"File\" can also be shared across a network, allowing users to access and collaborate on documents or other types of files.    Thus, VGA projector is the resource that is not usually shared in a network.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>14", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Factors to be considered when creating a backup system in a computer network include", "images": [], "options": {"A": "amount of RAM, amount of data and time of backup", "B": "amount of RAM, amount of data and frequency of backup", "C": "media to use, amount of data and frequency of backup", "D": "media to use, type of data and time of backup"}, "answer": "C", "explanation": "When creating a backup system in a computer network, the following factors should be considered:    - Media to use: The type of storage media to use for backups, such as external hard drives, tapes, or cloud storage.  - Amount of data: The total amount of data to be backed up, which determines the storage capacity required.  - Frequency of backup: How often backups should be performed, which depends on the importance of the data and how frequently it changes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>15", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET", "question": "The URL www.exams.edu.ng represents the website of", "images": [], "options": {"A": "an examination body", "B": "a Nigerian-based learning institution", "C": "an educational institution in Niger", "D": "a research institution in Niger"}, "answer": "B", "explanation": "The top-level domain \".edu.ng\" indicates an educational institution in Nigeria. The \".ng\" is the country code top-level domain (ccTLD) for Nigeria, and \".edu\" is used for educational institutions. Therefore, a URL with \".edu.ng\" generally represents a website of an educational institution based in Nigeria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>16", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "INFORMATION TRANSMISSION : INTERNET~~INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "The Post Office Protocol (POP) is used to", "images": [], "options": {"A": "interconnect devices on the Internet", "B": "retrieve email from a mail server", "C": "transfer file from a server to a client", "D": "send email from one user to another"}, "answer": "B", "explanation": "Post Office Protocol (POP) is a protocol used to retrieve email from a mail server to a local email client, such as a desktop or mobile email app. It allows users to download their email from the server to their local device for viewing and management.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>17", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM", "question": "A user working on a computer that is running on Windows 7 issued the command \"Crtl + Alt + Del\" while typing a document. What interface is expected to be displayed on the screen", "images": [], "options": {"A": "Restart Windows", "B": "Shut Down Windows", "C": "Windows Security", "D": "Windows Task Manager"}, "answer": "D", "explanation": "When a user presses \"Ctrl + Alt + Del\" on a Windows 7 computer, the Windows Task Manager will appear. This shortcut is used to open the Task Manager, which allows users to:    - View running processes and applications  - End tasks or processes  - Switch between users  - Lock the computer  - Log off", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>18", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Header and Footer are added to a document in Ms Word by just clicking on the", "images": [], "options": {"A": "Edit menu", "B": "Format menu", "C": "Insert menu", "D": "View menu"}, "answer": "C", "explanation": "In Microsoft Word, you can add headers and footers to a document by following these steps:    1. Click on the \"Insert\" menu.  2. Select \"Header\" or \"Footer\" from the drop-down menu.  3. Choose the desired header or footer style from the gallery.  4. Edit the header or footer content as needed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>19", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "A typist positioned the insertion point at the beginning of a line of text in a word processor and then pressed down the Shift key and clicked at the opposite end of the text. What would be the result of this action? The text will be", "images": [], "options": {"A": "copied into the clipboard", "B": "cut into the clipboard", "C": "deleted from the storage", "D": "highlighted on the screen"}, "answer": "D", "explanation": "When you press the Shift key and click at the opposite end of the text, it selects or highlights all the text between the insertion point and the point where you clicked. This is known as \"shift-click\" selection.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>20", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "The Microsoft Excel menu bar icon shown in Figure 2 is used to", "images": ["Data Processing/imgs/2024/GFWHJY.png"], "options": {"A": "automatically add up selected values", "B": "create label that spans multiple columns", "C": "spot trends and patterns in user's data using bars, columns and icons", "D": "organize data for easy analysis"}, "answer": "D", "explanation": "The figure above is the Sort & Filter icon. The tools are used for organizing and managing data.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>21", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "To add a new column to the right of the IGR column on the interface in Figure 3, the user would", "images": ["Data Processing/imgs/2024/C3Y3GT.png"], "options": {"A": "right-click on the cell C1 and then click on insert", "B": "right-click on the cell D1 and then click insert", "C": "right-click on column C and then click insert", "D": "right-click on column D and then click insert"}, "answer": "B", "explanation": "To add a new column to the right of the IGR column in an Excel workbook:    - Select the column to the right of the IGR column.  - Right-click the selected column header.  - Choose Insert from the context menu.    A new column will appear to the right of the IGR column.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>22", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The function of a foreign key in a database is to", "images": [], "options": {"A": "uniquely identify tuples in a table", "B": "provide a link between data in two tables", "C": "uniquely identify an entity occurrence", "D": "uniquely identify each record in a table"}, "answer": "B", "explanation": "A foreign key is a field in a table that references the primary key of another table, establishing a relationship between the two tables. It allows you to link data between tables, enabling queries and joins to retrieve related data.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2024>23", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Use  Figure 4  to answer questions  23  and  24.      How many primary keys exist in figure 4?", "images": ["Data Processing/imgs/2024/9M4BLM.png"], "options": {"A": "3", "B": "4", "C": "5", "D": "12"}, "answer": "A", "explanation": "A primary key is a unique identifier for a record in a table, and it is defined at the column level. A column can be designated as the primary key, ensuring that each value in that column is unique and identifies a single record.    The primary keys are \"CustomerId\" from \"Customers\" table, \"OrderId\" from \"Orders\" table, and \"ProductId\" from \"Products\" table.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2024>24", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Use  Figure 4  to answer questions  23  and  24.    Which of the following contains the primary keys in Figure 4?", "images": ["Data Processing/imgs/2024/9M4BLM.png"], "options": {"A": "Customers, Orders and Products", "B": "CustomerId, OrderId and ProductId", "C": "CustomerId, FirstName, LastName and DateCreated", "D": "Customers, CustomerId, FirstName, LastName and DateCreated"}, "answer": "A", "explanation": "A primary key is a unique identifier for a record in a table, and it is defined at the column level. A column can be designated as the primary key, ensuring that each value in that column is unique and identifies a single record.    The primary keys are \"CustomerId\" from \"Customers\" table, \"OrderId\" from \"Orders\" table, and \"ProductId\" from \"Products\" table.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>25", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "Web Design packages include the following except", "images": [], "options": {"A": "Macromedia Dreamweaver", "B": "iWeb", "C": "Front Page", "D": "Adobe Pagemaker"}, "answer": "D", "explanation": "Pagemaker is a desktop publishing software tool that was used for creating and designing print materials like brochures, magazines, and books. It's not a web design tool, so it's the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>26", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The part labelled IV in Figure 5 is used to", "images": ["Data Processing/imgs/2024/6NRYG4.png"], "options": {"A": "shape objects", "B": "select and transform objects", "C": "draw lines and curves", "D": "create texts"}, "answer": "C", "explanation": "The icon is the \"curved tool\" in CorelDraw.    The Curved Tool in CorelDRAW is a versatile tool used to create and edit curved lines and shapes. It offers a variety of options for customizing the shape and appearance of your curves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>27", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "One precautionary measure taken when cleaning a monitor is", "images": [], "options": {"A": "covering the monitor with antiglare", "B": "cleaning the monitor with alcohol", "C": "unplugging the power supply cable", "D": "using a vacuum cleaner to dust the monitor casing"}, "answer": "C", "explanation": "When cleaning a monitor, it's important to unplug the power supply cable to avoid any accidental start-ups or electrical shocks. This precautionary measure ensures your safety while cleaning the monitor.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>28", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER ETHICS", "question": "Which one of the following practices is considered ethical", "images": [], "options": {"A": "Gaining access into school database to change ones's grades", "B": "Gaining access into government database to alter personal details", "C": "Logging into a friend's social media account to read inbox messages", "D": "Signing into school e-library to read e-books"}, "answer": "D", "explanation": "The other options involve unauthorized access to private information or systems, which is a violation of privacy and security. Reading e-books from a school e-library is generally considered acceptable as it is within the intended use of the library's resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>29", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Proper network implementation and good ICT policies are types of", "images": [], "options": {"A": "adaptive measures", "B": "corrective measures", "C": "perfective measures", "D": "preventive measures"}, "answer": "D", "explanation": "Proper network implementation and good ICT policies are proactive measures taken to prevent potential security threats, data breaches, or technical issues. They aim to prevent problems from occurring in the first place, rather than reacting to them after they've happened.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>30", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Preventive maintenance measures in the computer room include the following options except", "images": [], "options": {"A": "good ventilation", "B": "proper illumination", "C": "the use of rugs", "D": "the use of tiles"}, "answer": "C", "explanation": "Preventive maintenance measures in a computer room aim to ensure a safe and reliable operating environment. While good ventilation and proper illumination are essential, the use of rugs is not recommended as they can generate dust and create a fire hazard.    Instead, floors are typically covered with tiles or other static-dissipative materials to reduce the risk of static electricity damage to sensitive equipment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>31", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Measures taken to avoid eye strain include the following except", "images": [], "options": {"A": "adjusting the brightness of the monitor", "B": "adjusting the height of the screen", "C": "blinking of eyes often", "D": "relaxing the body regularly"}, "answer": "D", "explanation": "The correct answer is: relaxing the body regularly.    Relaxing the body is generally good for overall health but is not directly related to preventing eye strain.  Adjusting the brightness of the monitor, adjusting the height of the screen, and blinking of eyes often are specific actions that help reduce eye strain during computer use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>32", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "A database administrator is responsible for the following tasks except", "images": [], "options": {"A": "controlling and monitoring user access to the database", "B": "enrolling users and maintaining system security", "C": "maintaining archived data", "D": "maintaining connection between local network and the Internet"}, "answer": "D", "explanation": "A database administrator (DBA) is responsible for managing and ensuring the performance, security, and integrity of a database. Their tasks include:    Controlling and monitoring user access to the database: Managing user privileges, access levels, and authentication.    Enrolling users and maintaining system security: Creating user accounts, managing passwords, and ensuring database security.    Maintaining archived data: Managing backup and recovery processes, storing and retrieving archived data.    However, maintaining the connection between the local network and the Internet is the responsibility of a network administrator, not a database administrator.    Other tasks that a DBA may perform include:    - Designing and implementing database structures  - Optimizing database performance  - Ensuring data consistency and integrity  - Troubleshooting database issues  - Updating and patching database software", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>33", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "A computer virus replicates itself into other programs on certain areas on the disk during the", "images": [], "options": {"A": "dormant phase", "B": "execution phase", "C": "propagation phase", "D": "trigger phase"}, "answer": "C", "explanation": "A computer virus replicates itself into other programs or areas of the disk during the propagation phase. This is the stage where the virus spreads and infects other parts of the system.    Here's a brief overview of the different phases of a computer virus:    Dormant phase: The virus remains inactive and hides in the system, waiting for a trigger to activate it.    Execution phase: The virus is executed and starts to run its malicious code.    Propagation phase: The virus replicates itself and spreads to other areas of the system or network.    Trigger phase: The virus is triggered to activate and start its malicious activities.    It's important to note that not all viruses follow this exact sequence, and some may have additional phases or variations on these phases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>34", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "A malware that copies and replicates itself using computer network and security flaws is", "images": [], "options": {"A": "Rootkit virus", "B": "Spyware", "C": "Trojan Horse", "D": "Worm"}, "answer": "D", "explanation": "A worm is a type of malware that can copy and replicate itself using computer network and security flaws, without needing to be sent as an attachment or downloaded. Worms exploit vulnerabilities in operating systems or applications to spread from system to system, often causing harm and consuming system resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>35", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The entities in Figure 6 are named", "images": ["Data Processing/imgs/2024/NXHXYC.png"], "options": {"A": "RegNo, Name and Age", "B": "Musa, Uche and Bayo", "C": "Student and Subject", "D": "Maths, Eng and DP"}, "answer": "C", "explanation": "In the context of database design and entity-relationship modeling (ERM), an entity refers to a concept or object that has existence and significance in the real world, not necessarily a table.    In a database, an entity is often represented as a table, but the entity itself is the conceptual object, not the table.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2024>36", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which one of the following statements is true about database tables?", "images": [], "options": {"A": "All the tables in a database have a common name", "B": "A table may contain repeating groups", "C": "Entries in a column are different from domains based on data type", "D": "There are no duplicate rows in a table"}, "answer": "D", "explanation": "There are no duplicate rows in a table is a true statement as relational database tables are designed to ensure that each row is unique. This uniqueness is often enforced by primary keys or unique constraints.     Duplicate rows can lead to inconsistencies and errors in the data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>37", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "The major difference between serial and sequential files is that sequential files are", "images": [], "options": {"A": "given a key", "B": "sorted in a particular order", "C": "sorted as they come", "D": "recorded in any storage medium"}, "answer": "B", "explanation": "Sequential files are organized in a specific order, such as alphabetical or numerical order, whereas serial files are not necessarily sorted in any particular order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>38", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "Which one of the following pairs contains computer file classification?", "images": [], "options": {"A": "Master file and Serial file", "B": "Random file and Master file", "C": "Reference file and Random file", "D": "Transaction file and Master file"}, "answer": "D", "explanation": "In computer file classification, files are usually categorized into two main types:    1. Master file: A permanent file that contains relatively stable data, such as customer information, product catalogs, or employee records. Master files are updated periodically and serve as a reference for other files.  2. Transaction file: A temporary file that contains data related to a specific transaction or event, such as sales orders, payment records, or inventory updates. Transaction files are typically used to update master files.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>39", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : DATABASE SECURITY", "question": "Which of the following statements support the goals of data backup?    I. Need for duplication  II. Need for future reference  III. Protection against data loss", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "Data backup goals are supported by all three statements:    I. Need for duplication: Backing up data creates a duplicate copy, ensuring that important files are not lost if the original is damaged or destroyed.    II. Need for future reference: Backed-up data can be used for future reference, such as auditing, historical analysis, or recovering previous versions of files.    III. Protection against data loss: The primary goal of data backup is to protect against data loss due to various threats, such as hardware failure, software corruption, human error, or natural disasters.    Data backup is essential for ensuring data availability, integrity, and recoverability. By duplicating data, storing it securely, and maintaining historical versions, backups support all three goals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2024>40", "subject": "Data Processing", "year": "2024", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Which of the following characteristics is associated with the architecture of parallel database?", "images": [], "options": {"A": "Communication cost and problems cannot be ignored", "B": "Machines can be far from each other", "C": "Machines are physically close to each other", "D": "It is usually associated with shared-nothing architecture"}, "answer": "D", "explanation": "Parallel databases are designed to distribute data and processing across multiple machines to improve performance and scalability.    A shared-nothing architecture is a common approach in parallel databases, where each node has its own independent memory and storage. This architecture minimizes communication overhead and improves fault tolerance, making it well-suited for large-scale data processing applications.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2025>1", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "The  Difference Engine  was developed by", "images": [], "options": {"A": "Blaise Pascal.", "B": "Charles Babbage.", "C": "Herman Hollerith.", "D": "John Von Neumann."}, "answer": "B", "explanation": "The Difference Engine was designed by Charles Babbage in the early 19th century (1820s). It was a mechanical calculator intended to automate polynomial calculations (e.g., for navigation tables), eliminating human errors.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>2", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING", "question": "Convert A0BHEX​ to a number in binary.", "images": [], "options": {"A": "1010010112", "B": "1011010102", "C": "1010000010112", "D": "1011000010102"}, "answer": "C", "explanation": "Breaking down each hexadecimal digit into its 4-bit binary equivalent:    Hexadecimal digits (0-F) correspond to the following binary values:    Hex\tBinary0\t00001\t00012\t00103\t00114\t01005\t01016\t01107\t01118\t10009\t1001A\t1010B\t1011C\t1100D\t1101E\t1110F\t1111  Converting each digit of A0BHEX:    A → 1010    0 → 0000    B → 1011    Combining the binary digits in order:    &nbsp;&nbsp;&nbsp;&nbsp;A&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;   0&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;   B  1010 0000 1011    Result: 101000001011₂", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>3", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Audio data are produced from", "images": [], "options": {"A": "animations.", "B": "graphics.", "C": "pictures.", "D": "sounds."}, "answer": "D", "explanation": "Audio data by its very definition refers to data that represents sound. It is created by capturing, digitizing, and storing sound waves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>4", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which of the following variables is an example of numeric data?", "images": [], "options": {"A": "568", "B": "B2", "C": "₦10.00", "D": "Twenty-five"}, "answer": "A", "explanation": "568 is a pure number — an example of numeric data.    B2 is alphanumeric (a mix of letter and number).    ₦10.00 includes a currency symbol, so it's not strictly numeric.    Twenty-five is a textual (string) representation of a number.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>5", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : HISTORY OF COMPUTERS", "question": "The generation of computers in which transistor was first introduced is the", "images": [], "options": {"A": "fifth generation.", "B": "fourth generation.", "C": "second generation.", "D": "third generation."}, "answer": "C", "explanation": "First generation computers used vacuum tubes.    Second generation computers introduced transistors, replacing vacuum tubes — this made computers smaller, faster, and more reliable.    Third generation used integrated circuits (ICs).    Fourth generation used microprocessors.    Fifth generation is based on artificial intelligence and advanced parallel processing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>6", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE", "question": "One application of  ICT  in medicine is", "images": [], "options": {"A": "Computer Aided Learning.", "B": "Computer Aided Manufacturing.", "C": "Computerized Axial Tomography.", "D": "Optical Character Recognition."}, "answer": "C", "explanation": "Computerized Axial Tomography (CAT), more commonly known as CT scans, is a medical imaging technique that uses X-rays and computer processing to create cross-sectional images (slices) of bones, blood vessels, and soft tissues inside your body. This is a direct and significant application of Information and Communication Technology (ICT) in medicine.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>7", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : CLASSIFICATION OF COMPUTERS", "question": "Which one of the following reasons justifies the prevalence of Personal Digital Assistance devices? They", "images": [], "options": {"A": "are lightweight and very expensive.", "B": "are very portable and can be used everywhere.", "C": "have limited capabilities compared to desktop and laptop computers.", "D": "have small keyboards for input operation."}, "answer": "B", "explanation": "Personal Digital Assistants (PDAs), while somewhat superseded by smartphones now, were designed specifically for portability. Their primary appeal was their compact size, allowing users to carry them easily and access information, schedules, and basic applications on the go, virtually anywhere.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>8", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "Which one of the following actions can be achieved by right-clicking a computer mouse?", "images": [], "options": {"A": "Closing of the current windows", "B": "Display of dialog box", "C": "Minimizing of active windows", "D": "Opening of contextual menus"}, "answer": "D", "explanation": "When you right-click a mouse on most operating systems (like Windows or macOS), it brings up a contextual menu — a list of options relevant to the object or area where the click occurred (e.g., desktop, file, or hyperlink).", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>9", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The manipulation of digitized information by computer or other digital electronic equipment is known as:", "images": [], "options": {"A": "data collation.", "B": "data mining.", "C": "information gathering.", "D": "information processing."}, "answer": "D", "explanation": "Information processing refers to the manipulation, organization, and analysis of digitized data using computers or digital devices. It encompasses:    Input: Capturing data (e.g., via keyboards, sensors).    Processing: Transforming data (e.g., calculations, sorting).    Output: Presenting results (e.g., reports, visualizations).    Storage: Saving data for future use.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>10", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "Which one of the following statements does not explain information processing?", "images": [], "options": {"A": "Act of saving documents", "B": "Changing of information detectable by an observer", "C": "Conversion of raw data into information", "D": "Process that describes everything that happens to a piece of information"}, "answer": "A", "explanation": "Information processing involves transforming or manipulating data to produce meaningful output. While saving documents is part of data management, it does not inherently involve processing (e.g., analysis, conversion, or interpretation).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>11", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION AGE : DATA AND INFORMATION", "question": "The part labelled X in Figure 1 is called", "images": ["Data Processing/imgs/2025/33REAJ.jpg"], "options": {"A": "analysis.", "B": "evaluation.", "C": "feedback.", "D": "retreat."}, "answer": "C", "explanation": "The image shows a diagram labeled \"Figure 1: Information Cycle\" with blocks for \"Input,\" \"Decision making,\" and \"Output.\" There's a loop from \"Output\" back towards \"Input,\" with a block labeled \"X\" in the middle of this loop.    This cycle represents how information is processed and refined over time. After information is output, it's often evaluated, and the results of that evaluation (X) are fed back into the input stage to improve future decision-making or processing. This iterative process is characteristic of systems that learn or adapt.    Therefore, the part labeled X, representing the flow from output back to input to influence subsequent processes, is best described as feedback.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>12", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Which one of the following gadgets allows the transmission of both visual and audio information?", "images": [], "options": {"A": "Facsimile", "B": "Radio", "C": "Television", "D": "Walkie-Talkie"}, "answer": "C", "explanation": "Television is the only gadget among the options that transmits both visual (video) and audio (sound) information simultaneously. It combines:    Visual data: Images, videos, text (e.g., news broadcasts, movies).    Audio data: Soundtracks, dialogues, music.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>13", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Use Figure 2 to answer questions 13 and 14.      The underlying technology in the network connection in Figure 2 is called", "images": ["Data Processing/imgs/2025/K4HTBA.jpg"], "options": {"A": "Bluetooth.", "B": "Ethernet.", "C": "Laser Jet.", "D": "Optical Fibre."}, "answer": "A", "explanation": "Since Figure 2 explicitly shows a Bluetooth network, the underlying technology is Bluetooth, a wireless standard for short-range data exchange (e.g., connecting phones to headphones).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>14", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : NETWORKING", "question": "Use Figure 2 to answer questions 13 and 14.    One limitation of the network type in Figure 2 is that", "images": ["Data Processing/imgs/2025/K4HTBA.jpg"], "options": {"A": "cost of maintenance is high.", "B": "distance covered is short.", "C": "resources that can be shared are selective.", "D": "weather can affect the rate of data sharing."}, "answer": "B", "explanation": "Bluetooth networks operate over short distances, typically up to 10 meters (33 feet) for most devices, though some can go up to 100 meters with reduced data rate.    This limited range is a key limitation of Bluetooth when compared to other wireless technologies like Wi-Fi.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>15", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Use Figure 3 to answer questions 15 and 16.      The interface in Figure 3 is used for", "images": ["Data Processing/imgs/2025/44DM87.jpg"], "options": {"A": "creating new sites.", "B": "creating portable documents.", "C": "sending and receiving e-mails.", "D": "sending and receiving SMS."}, "answer": "C", "explanation": "Email interfaces (e.g., Gmail, Outlook) commonly feature:    - A search bar (to find emails).    - A placeholder (e.g., \"Search mail\" or \"Compose new email\").    Thererefore the interface in Figure 3 is used for sending and receiving e-mails.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>16", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION", "question": "Use Figure 3 to answer questions 15 and 16.    The part labelled III in Figure 3 is used for", "images": ["Data Processing/imgs/2025/44DM87.jpg"], "options": {"A": "keeping draft portable documents.", "B": "keeping unfinished sites.", "C": "saving unsent e-mails.", "D": "saving unsent SMS."}, "answer": "C", "explanation": "In email applications:    The \"Drafts\" folder is used to store email messages that have been written but not yet sent.    This allows users to return later to complete or send them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>17", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "What happens when the Shift key is pressed while deleting a file from the computer in Windows? The file is", "images": [], "options": {"A": "uninstalled from the computer.", "B": "permanently deleted from the computer.", "C": "deleted and sent to the Recycle Bin.", "D": "deleted and kept in the clipboard."}, "answer": "B", "explanation": "In Windows, when you delete a file:    Pressing Delete alone sends the file to the Recycle Bin (you can restore it later).    Pressing Shift + Delete bypasses the Recycle Bin and permanently deletes the file. It cannot be restored unless you use special recovery software.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>18", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Figure 4 is a full set of page formatting options captured from MS Word application.  Use it to answer questions 18 and 19.      A user who was typing a document in portrait orientation decided to complete the next few pages in landscape orientation. Which one of the following options illustrates the correct order of steps the user must follow by clicking on the labelled parts to achieve this?", "images": ["Data Processing/imgs/2025/REAALF.jpg"], "options": {"A": "I, III and V", "B": "I, IV and V", "C": "II, III and V", "D": "II, IV and V"}, "answer": "D", "explanation": "To switch from portrait to landscape orientation for specific pages in MS Word:    1. Step II (Landscape Orientation):    Click the Landscape option under \"Orientation\" to change the layout.    2. Step IV (Apply to Whole Document):    In the \"Apply to\" dropdown, select Whole document to ensure consistency or This section if using section breaks.    3. Step V (OK):    Confirm the changes by clicking OK.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>19", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING", "question": "Figure 4 is a full set of page formatting options captured from MS Word application.  Use it to answer questions 18 and 19.    Which one of these options gives the correct order of steps to revert to portrait orientation after typing in landscape orientation for a while?", "images": ["Data Processing/imgs/2025/REAALF.jpg"], "options": {"A": "I, III and V", "B": "I, IV and V", "C": "II, III and V", "D": "II, IV and V"}, "answer": "B", "explanation": "To revert from landscape to portrait orientation in MS Word:    1. Step I (Portrait Orientation):    Click the Portrait option under \"Orientation\" to switch back to the default vertical layout.    2. Step IV (Apply to Whole Document):    Select Whole document (or \"This section\" if using section breaks) to ensure the change applies to all pages.    3. Step V (OK):    Confirm the action by clicking OK.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>20", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "What happens when a user clicks on the Microsoft Excel menu bar icon shown in Figure 5?", "images": ["Data Processing/imgs/2025/2ELAJP.jpg"], "options": {"A": "A copy of the selection is put on the clipboard", "B": "A label that spans multiple columns is created", "C": "Content on the clipboard is added to the insertion point", "D": "Selected range of cells is quickly converted to a table with its own style"}, "answer": "C", "explanation": "The image in Figure 5 shows an icon that typically represents the \"Paste\" function in Microsoft Excel (and many other Windows applications). It looks like a clipboard with a document or sheet of paper being \"pasted\" onto it.    Therefore, the icon shown in Figure 5, which depicts a clipboard with a document, represents the Paste action.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>21", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : SPREADSHEET", "question": "To add a new row above EKITI on the MS Excel interface shown in Figure 6, the user would right-click on", "images": ["Data Processing/imgs/2025/F99PJC.jpg"], "options": {"A": "cell A5 and then click on insert.", "B": "cell A6 and then click on insert.", "C": "row 5 and then click on insert.", "D": "row 6 and then click on insert."}, "answer": "D", "explanation": "Since EKITI is in cell A6, and you want to add a new row above EKITI , you need to insert a row at row 6, which will push EKITI down.    To do that in MS Excel:    You right-click on row 6, and then select Insert.    This inserts a new row above row 6, moving EKITI to row 7.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>22", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Which one of the following points is not considered when designing a database in Microsoft Access? Determine", "images": [], "options": {"A": "how forms will be used.", "B": "how tables will be related.", "C": "the data needed.", "D": "the purpose of the database."}, "answer": "A", "explanation": "When designing a database in Microsoft Access, the primary focus is on structural and functional requirements, not interface tools like forms. Key considerations include:    1. Purpose of the database → Defines the scope and goals (e.g., inventory tracking).    2. Data needed → Identifies tables/fields (e.g., ProductID, ProductName).    3. Table relationships → Establishes links (e.g., one-to-many between Customers and Orders).", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>23", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "Tables in Microsoft Access are created using the following methods except", "images": [], "options": {"A": "Datasheet view.", "B": "Design view.", "C": "Table insertion.", "D": "Table wizard."}, "answer": "C", "explanation": "In Microsoft Access, tables can be created using the following methods:    1. Datasheet View: Start entering data directly, and Access generates a table structure automatically.    2. Design View: Manually define fields, data types, and properties (most precise method).    3. Table Wizard: Use pre-built templates to create tables quickly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>24", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE", "question": "The keyboard shortcut for adding a new slide to Microsoft PowerPoint application is", "images": [], "options": {"A": "Ctrl + H.", "B": "Ctrl + M.", "C": "Alt + H.", "D": "Alt + M."}, "answer": "B", "explanation": "In Microsoft PowerPoint, the keyboard shortcut Ctrl + M quickly adds a new slide to your presentation. This shortcut works in all recent versions of PowerPoint (2010, 2013, 2016, 2019, 2021, 365).", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>25", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES", "question": "An example of web design software is", "images": [], "options": {"A": "CSS.", "B": "MS Outlook.", "C": "MS Publisher.", "D": "SPSS."}, "answer": "C", "explanation": "MS Publisher is a desktop publishing application that can also be used to design simple websites or web pages.    CSS is a style sheet language, not a software.    MS Outlook is an email client.    SPSS is used for statistical analysis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>26", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES", "question": "The part labelled VII in Figure 7 is used to", "images": ["Data Processing/imgs/2025/HY6MYP.jpg"], "options": {"A": "shape objects.", "B": "select and transform objects.", "C": "draw lines and curves.", "D": "create texts."}, "answer": "D", "explanation": "In CorelDRAW, the Text Tool is used to create and edit text within your design. It is represented by the letter \"A\" and is often located in the toolbox on the left side of the interface", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>27", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The erratic movement of the mouse pointer is usually caused by", "images": [], "options": {"A": "bad connection.", "B": "dirty mouse ball.", "C": "driver error.", "D": "hardware failure."}, "answer": "B", "explanation": "In older mechanical mice (ball-type), erratic pointer movement is commonly caused by a dirty mouse ball or buildup of dirt on the rollers inside the mouse. Cleaning the mouse ball usually resolves the issue.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>28", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "The suitable method of removing particles from the keyboard is by", "images": [], "options": {"A": "cleaning with dripping wet cloth.", "B": "cleaning with iron brush.", "C": "using compressed air.", "D": "using hot air."}, "answer": "C", "explanation": "Compressed air is the safest and most effective method to remove dust and particles from between the keys of a keyboard without causing damage. It blows debris out from hard-to-reach areas without needing to disassemble the keyboard.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>29", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : SAFETY MEASURES", "question": "Which one of the following statements is true about preventing phishing?", "images": [], "options": {"A": "Ensure that antivirus is updated regularly", "B": "Do not click on links in e-mails from unknown sources", "C": "Do not download from untrusted sites", "D": "Use a strong password at all times"}, "answer": "B", "explanation": "Phishing involves tricking users into clicking malicious links in fake emails that appear legitimate. Avoiding clicks on links from unknown or suspicious sources is a primary defense against phishing attacks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>30", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "Preventative maintenance measures in the computer room include the following except", "images": [], "options": {"A": "good ventilation.", "B": "maintaining dust-free environments.", "C": "proper illumination.", "D": "the use of rugs on the floor."}, "answer": "D", "explanation": "Using rugs in a computer room is not recommended because they can accumulate static electricity and dust, both of which can damage computer equipment. On the other hand, good ventilation, dust-free environments, and proper lighting are all valid preventative maintenance measures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>31", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : MAINTENANCE OF COMPUTER", "question": "When cleaning the computer system, it is advisable to", "images": [], "options": {"A": "restart the computer first.", "B": "turn off the computer and disconnect from power source.", "C": "use antiglare cover to protect the screen.", "D": "use multimeter tester for earthing."}, "answer": "B", "explanation": "Before cleaning any computer system, it is essential to power it off and unplug it from the electrical source to prevent electric shock or damage to the system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>32", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING", "question": "A system analyst is a professional who", "images": [], "options": {"A": "designs flowcharts.", "B": "designs and implements new computer-based solutions.", "C": "trains computer users on new solutions.", "D": "writes complex computer programs."}, "answer": "B", "explanation": "A system analyst studies an organization's current systems and processes and designs new computer-based solutions to improve efficiency and effectiveness. They may also be involved in implementation and coordination with developers and users.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>33", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "Which one of the following programs is not a type of virus?", "images": [], "options": {"A": "Boot sector virus", "B": "Logic bomb", "C": "Polymorphic virus", "D": "Trojan horse"}, "answer": "D", "explanation": "A Trojan horse (or simply \"Trojan\") is a type of malware that disguises itself as legitimate software or tricks users into installing it. Unlike viruses, Trojans do not self-replicate by infecting other files. They rely on deception to spread. Once installed, they can perform various malicious activities. This is a type of malware, but NOT a type of virus.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>34", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "ETHICS AND HUMAN ISSUES : COMPUTER VIRUS", "question": "The computer virus accesses the user's computer and and waits for a trigger during the", "images": [], "options": {"A": "dormant phase.", "B": "execution phase.", "C": "propagation phase.", "D": "trigger phase."}, "answer": "A", "explanation": "In the dormant phase, the virus is present in the system but remains inactive and waits silently for a trigger event before executing its payload.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2025>35", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "The SQL constraint used to ensure the accuracy and consistency of data in a relational database is called", "images": [], "options": {"A": "default constraint.", "B": "index constraint.", "C": "integrity constraint.", "D": "unique constraint."}, "answer": "C", "explanation": "Integrity constraints in SQL are rules applied to database tables to ensure:    1. Accuracy: Data meets predefined conditions (e.g., NOT NULL).    2. Consistency: Relationships between tables are valid (e.g., foreign keys).    Types of Integrity Constraints:    Entity Integrity: Primary keys (PRIMARY KEY) enforce unique, non-null rows.    Referential Integrity: Foreign keys (FOREIGN KEY) maintain valid links between tables.    Domain Integrity: Data type/format rules (e.g., CHECK, DEFAULT).", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>36", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "DATA MANAGEMENT : RELATIONAL MODEL", "question": "To create a one-to-one relationship in database, it is necessary that", "images": [], "options": {"A": "both primary and foreign key fields should have multiple key index.", "B": "both primary and foreign key fields should have unique key index.", "C": "only the foreign key field should have a unique index.", "D": "only the primary key field should have a unique index."}, "answer": "B", "explanation": "In a one-to-one relationship, each record in both tables must be unique and correspond to only one record in the other table. Therefore, both the primary key and foreign key fields must have unique constraints (unique indexes) to enforce this.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>37", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "DATA MANAGEMENT : FILE ORGANIZATION", "question": "An advantage of manual file over computer file is that", "images": [], "options": {"A": "it is more efficient.", "B": "it requires less storage space.", "C": "risk of corrupted data is much less.", "D": "speed of processing is high."}, "answer": "C", "explanation": "Manual files are physical records, so they cannot be corrupted by software errors or viruses like computer files can. However, they are generally less efficient, slower, and require more physical storage space compared to computer files.", "marks": "1", "difficulty": "1"}, {"id": "objective>Data Processing>2025>38", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "BASIC COMPUTING : COMPONENTS OF COMPUTERS", "question": "A user observed that a certain file in a removable storage device changed to a shortcut icon. This implies that", "images": [], "options": {"A": "the file is corrupt.", "B": "the file is shared.", "C": "the removable storage device is corrupt.", "D": "there is a link to the file."}, "answer": "D", "explanation": "When a file changes to a shortcut icon, it means the original file is linked by a shortcut, not the actual file itself. Sometimes this happens if malware creates shortcuts instead of showing the real files, but fundamentally, a shortcut is a link pointing to the file's location.", "marks": "1", "difficulty": "2"}, {"id": "objective>Data Processing>2025>39", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM", "question": "The objectives to consider while designing a secure database application include the following except", "images": [], "options": {"A": "simplicity.", "B": "secrecy.", "C": "integrity.", "D": "availability."}, "answer": "A", "explanation": "When designing a secure database application, the main objectives typically focus on secrecy (confidentiality), integrity, and availability — often referred to as the CIA triad in security. Simplicity is not a core security objective, though it may be desirable for usability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Data Processing>2025>40", "subject": "Data Processing", "year": "2025", "type": "Objective", "topic": "DATA MANAGEMENT : PARALLEL AND DISTRIBUTED DATABASES", "question": "Which one of the following features is not an advantage of distributed database?", "images": [], "options": {"A": "Better response", "B": "Lower communication cost.", "C": "Improved reliability.", "D": "Need for complex software."}, "answer": "D", "explanation": "The need for complex software is actually a disadvantage of distributed databases, not an advantage. Distributed databases improve response time, reduce communication costs, and enhance reliability, but they require more complex software to manage data distribution and synchronization.", "marks": "1", "difficulty": "2"}];